import { GraphQLClient, RequestOptions } from 'graphql-request';
import gql from 'graphql-tag';
export type Maybe<T> = T | null;
export type InputMaybe<T> = Maybe<T>;
export type Exact<T extends { [key: string]: unknown }> = { [K in keyof T]: T[K] };
export type MakeOptional<T, K extends keyof T> = Omit<T, K> & { [SubKey in K]?: Maybe<T[SubKey]> };
export type MakeMaybe<T, K extends keyof T> = Omit<T, K> & { [SubKey in K]: Maybe<T[SubKey]> };
export type MakeEmpty<T extends { [key: string]: unknown }, K extends keyof T> = { [_ in K]?: never };
export type Incremental<T> = T | { [P in keyof T]?: P extends ' $fragmentName' | '__typename' ? T[P] : never };
type GraphQLClientRequestHeaders = RequestOptions['requestHeaders'];
/** All built-in and custom scalars, mapped to their actual values */
export type Scalars = {
  ID: { input: string; output: string; }
  String: { input: string; output: string; }
  Boolean: { input: boolean; output: boolean; }
  Int: { input: number; output: number; }
  Float: { input: number; output: number; }
  /** The `Any` scalar any type */
  Any: { input: any; output: any; }
  /** The `ArrayLike` scalar type represents a reference to a store previously created by the user n a datalayer */
  ArrayLike: { input: any; output: any; }
  /** Date with time (isoformat) */
  DateTime: { input: any; output: any; }
  /** A quantity of time (``"5 ms"``, ``"2 s"``, ``"1 hour"``). */
  Duration: { input: any; output: any; }
  /** The `FileLike` scalar type represents a reference to a big file storage previously created by the user n a datalayer */
  FileLike: { input: any; output: any; }
  /** The `Vector` scalar type represents a matrix values as specified by */
  FiveDVector: { input: any; output: any; }
  /** The `FourByFourMatrix` scalar type represents a matrix values as specified by */
  FourByFourMatrix: { input: any; output: any; }
  /** A quantity of frequency (``"50 Hz"``, ``"1 kHz"``). */
  Frequency: { input: any; output: any; }
  /**
   * A physical quantity of any dimension (``"0.12 S/cm2"``, ``"-54.3 mV"``, ``"2 mM"``).
   *
   * Unlike the dimension-locked scalars, this keeps whatever unit the value
   * carries and does not normalize to a canonical integer — its dimension is
   * whatever the value has. A bare number without a unit is rejected. On the wire
   * it is a string; validating it against an expected dimension (e.g. a declared
   * mechanism parameter) is the caller's job.
   */
  GenericQuantity: { input: any; output: any; }
  /** The `ImageFileLike` scalar type represents a reference to a snapshot image previously created by the user n a datalayer */
  ImageFileLike: { input: any; output: any; }
  /** The `ImageLike` scalar type represents a reference to an image previously created by the user in a datalayer */
  ImageLike: { input: any; output: any; }
  /** The `JSON` scalar type represents JSON values as specified by [ECMA-404](https://ecma-international.org/wp-content/uploads/ECMA-404_2nd_edition_december_2017.pdf). */
  JSON: { input: any; output: any; }
  /** The `LabelsLike` scalar type represents a reference to a labels object previously created by the user n a datalayer */
  LabelsLike: { input: any; output: any; }
  /** A spatial length (``"2.5 µm"``, ``"1 mm"``, ``"3 m"``). */
  Length: { input: any; output: any; }
  /** The `MetricMap` scalar type represents a matrix values as specified by */
  MetricMap: { input: any; output: any; }
  /** The `ParquetLike` scalar type represents a reference to a parquet objected stored previously created by the user on a datalayer */
  ParquetLike: { input: any; output: any; }
  /** A power (``"5 mW"``, ``"2 W"``). */
  Power: { input: any; output: any; }
  /** A temperature (``"310 K"``, ``"37 degC"``). */
  Temperature: { input: any; output: any; }
  /** The `Vector` scalar type represents a matrix values as specified by */
  ThreeDVector: { input: any; output: any; }
  UUID: { input: any; output: any; }
  /**
   * A physical unit of measurement (``"mV"``, ``"S/cm2"``, ``"second"``).
   *
   * A string scalar validating that the value parses as a pint unit — a bad unit,
   * a bare quantity (``"5 mV"``), or a dimension is rejected. Compact exponent
   * spelling (``"cm2"``) is accepted and the given spelling is preserved.
   */
  Unit: { input: any; output: any; }
  _Any: { input: any; output: any; }
};

/** A multi-dimensional array dataset. Its dimensions and their types live on the axes of its INTRINSIC (pixel grid) coordinate system; physical units live on its calibrations; its pyramid levels are DataArrays, each mapping into the one intrinsic system */
export type ADataset = {
  __typename?: 'ADataset';
  /** The dataset's axis names, in array order. Derived from the axes of its intrinsic coordinate system */
  axisNames: Array<Scalars['String']['output']>;
  /** The dataset's calibrated PHYSICAL spaces (pixel size, stage pose, ...). Each is reached from the intrinsic system by a single transformation edge; refining a calibration bumps that edge's version and moves nothing drawn in pixels */
  calibrations: Array<CoordinateSystem>;
  /** The task this dataset was created through, if any */
  createdThrough?: Maybe<Task>;
  /** The assigner of the creating task, if any */
  createdThroughBy?: Maybe<User>;
  /** The multiscale data arrays belonging to this dataset */
  dataArrays: Array<DataArray>;
  /** The datasets computed from this one -- the other end of `derivedFrom`, and the way to ask what a source produced: the deconvolutions, segmentations and projections that named a space of this dataset as their parent. Derived from the same edges, never a stored back-reference that could disagree with them. Every child, not just those this dataset places: a fusion that named this source second is listed here, and so is a child whose derivation is UNMAPPABLE -- it came from here even though its geometry did not survive. The maps themselves are on each child's own `derivedFrom` */
  derivedDatasets: Array<ADataset>;
  /** The edges from this dataset's pixel grid back into the lenses it was computed from, when it is a derived dataset: one for a deconvolution or a resample, several for a fusion of channels or tiles. Empty for a dataset that was acquired rather than derived. The order is the priority its creator declared: the first edge is the primary parent, the one that places the dataset. They are edges, not labels: each carries the map itself, so a client can compose it -- and they are why a derived dataset inherits its sources' placements instead of needing its own registration */
  derivedFrom: Array<Transformation>;
  description?: Maybe<Scalars['String']['output']>;
  id: Scalars['ID']['output'];
  /** The dataset's INTRINSIC coordinate system: its level-0 pixel grid, the space every pyramid level and lens maps into and the space ROIs resolve against. Structural and calibration-independent */
  intrinsicSystem?: Maybe<CoordinateSystem>;
  /** The most recent picture that shows this dataset and nothing else, for previewing it without loading the array. Snapshots are taken of scenes, not of datasets, so this only answers with a scene whose *only* placed dataset is this one -- a picture blending several datasets is a preview of none of them. Null when every scene it is placed in also holds other data. Two caveats it cannot rule out: the dataset may be placed in that scene without any layer drawing it (the picture can be empty), and a mesh or table collection may be drawn over it as an annotation */
  latestSnapshot?: Maybe<SceneSnapshot>;
  /** Whether this dataset carries a resolution pyramid. Derived: true when it has more than one level */
  multiscale: Scalars['Boolean']['output'];
  name: Scalars['String']['output'];
  /** Every change made to this dataset: who created it, and every subsequent rename or redescription, attributed to the client, user and task it happened under. Only `name` and `description` can change -- the arrays, the axes and the coordinate systems built from them are fixed at creation */
  provenanceEntries: Array<ProvenanceEntry>;
  /** The scenes this dataset is rendered in, reached through its lenses' layers. Derived, never stored: a scene is a composition and this is a fact of the graph, so there is no dataset-to-scene column that could disagree with it. The scene createADataset's bootstrapScene creates is found here */
  scenes: Array<Scene>;
  /** The dataset's shape: that of its level-0 array */
  shape: Array<Scalars['Int']['output']>;
  /** What this dataset structurally is, materialized from the axes of its intrinsic coordinate system at creation: the one spatial spec its SPACE axis count denotes, then a modifier per acquisition axis present. A 3D timelapse is [VOLUME, TIMESERIES, MULTICHANNEL]. Presence, not size: a stack with a single plane is still a VOLUME. Empty while the intrinsic system does not exist yet */
  spec: Array<ADatasetSpec>;
};


/** A multi-dimensional array dataset. Its dimensions and their types live on the axes of its INTRINSIC (pixel grid) coordinate system; physical units live on its calibrations; its pyramid levels are DataArrays, each mapping into the one intrinsic system */
export type ADatasetCalibrationsArgs = {
  filters?: InputMaybe<CoordinateSystemFilter>;
  ordering?: Array<CoordinateSystemOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A multi-dimensional array dataset. Its dimensions and their types live on the axes of its INTRINSIC (pixel grid) coordinate system; physical units live on its calibrations; its pyramid levels are DataArrays, each mapping into the one intrinsic system */
export type ADatasetDataArraysArgs = {
  filters?: InputMaybe<DataArrayFilter>;
  ordering?: Array<DataArrayOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A multi-dimensional array dataset. Its dimensions and their types live on the axes of its INTRINSIC (pixel grid) coordinate system; physical units live on its calibrations; its pyramid levels are DataArrays, each mapping into the one intrinsic system */
export type ADatasetProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type ADatasetFilter = {
  AND?: InputMaybe<ADatasetFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<ADatasetFilter>;
  OR?: InputMaybe<ADatasetFilter>;
  /** Filter by the sub of the user that assigned the creating task */
  assignedBy?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by whether the dataset carries at least one PHYSICAL calibration -- a space with real units. False finds the data that is still only pixels, with no pixel size or stage pose recorded. Unrelated to a phasor histogram's `calibrated`, which is about reference correction */
  calibrated?: InputMaybe<Scalars['Boolean']['input']>;
  /** Filter for items created after this datetime */
  createdAfter?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter for items created before this datetime */
  createdBefore?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter by the database ID of the task the item was created through (the `createdThrough { id }` field) */
  createdThrough?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the database ID of the user that assigned the creating task (the `createdThroughBy { id }` field) */
  createdThroughBy?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the rekuest task id the item was created through */
  createdThroughTask?: InputMaybe<Scalars['String']['input']>;
  /** Filter to the datasets computed from this one -- the deconvolutions, segmentations and projections that named a space of it as their parent. Every child, not just the ones it places: a fusion that named it second is listed, and so is a child whose derivation is UNMAPPABLE, since it still came from here */
  derivedFrom?: InputMaybe<Scalars['ID']['input']>;
  description?: InputMaybe<StrFilterLookup>;
  /** Filter to datasets whose intrinsic coordinate system carries every one of these axis types, e.g. [TIME, CHANNEL]. The raw form of `spec`, for the types no spec names: COORDINATE, DISPLACEMENT, INDEX */
  hasAxisTypes?: InputMaybe<Array<AxisType>>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  /** Filter by whether the dataset carries a resolution pyramid: true for the multiscale ones, false for those with a single level */
  multiscale?: InputMaybe<Scalars['Boolean']['input']>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter for datasets that were acquired rather than computed: true for the roots, those with no derivation edge into another dataset's space */
  notDerived?: InputMaybe<Scalars['Boolean']['input']>;
  /** Filter by the creator's subject ID */
  owner?: InputMaybe<Scalars['ID']['input']>;
  /** Filter to datasets placeable into this scene: those with a lens whose space has a traversable path to the scene's world, walking the transformation edges. What could be staged there -- for what already is, use `scene` */
  placeableIn?: InputMaybe<Scalars['ID']['input']>;
  /** Filter to datasets rendered in this scene, through their lenses' layers. What is actually staged there -- for what merely could be, use `placeableIn` */
  scene?: InputMaybe<Scalars['ID']['input']>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
  /** Filter to datasets satisfying every one of these specs, e.g. [VOLUME, TIMESERIES] for 3D timelapses. Materialized from the axes of the intrinsic coordinate system at creation. A dataset carries one spatial spec (by how many SPACE axes it has) plus a modifier per acquisition axis present, so two spatial specs together match nothing */
  spec?: InputMaybe<Array<ADatasetSpec>>;
};

export type ADatasetOrder =
  { createdAt: Ordering; id?: never; name?: never; }
  |  { createdAt?: never; id: Ordering; name?: never; }
  |  { createdAt?: never; id?: never; name: Ordering; };

/** What a dataset structurally is, materialized from the axes of its intrinsic coordinate system at creation. Specs stack: a 3D timelapse is VOLUME, TIMESERIES and MULTICHANNEL at once. Exactly one spatial member (SCALAR/PROFILE/IMAGE/VOLUME/HYPERVOLUME) ever holds. */
export enum ADatasetSpec {
  /** Carries a MICROTIME axis: fluorescence-lifetime arrival-time bins. */
  Flim = 'FLIM',
  /** Four or more spatial axes. */
  Hypervolume = 'HYPERVOLUME',
  /** Two spatial axes: a plane. The ordinary micrograph. */
  Image = 'IMAGE',
  /** Carries a CHANNEL axis. Presence only: a one-channel axis still counts. */
  Multichannel = 'MULTICHANNEL',
  /** One spatial axis -- a line profile, a depth trace. */
  Profile = 'PROFILE',
  /** No spatial extent: the array carries no SPACE axis at all. */
  Scalar = 'SCALAR',
  /** Carries a SPECTRUM axis: a spectrally resolved acquisition, a lambda stack. */
  Spectral = 'SPECTRAL',
  /** Carries a TIME axis -- a timelapse. Presence only: a single-frame time axis still counts. */
  Timeseries = 'TIMESERIES',
  /** Three spatial axes: a stack. Holds whenever a z axis is present, even if it carries a single plane. */
  Volume = 'VOLUME'
}

/** An accessor declares how the values of specific columns (keys) of a table should be interpreted, e.g. as pixel labels of a mask or as ids of images. */
export type Accessor = {
  id: Scalars['ID']['output'];
  keys: Array<Scalars['String']['output']>;
  maxIndex?: Maybe<Scalars['Int']['output']>;
  minIndex?: Maybe<Scalars['Int']['output']>;
  table: Table;
};

export type AccessorFilter = {
  AND?: InputMaybe<AccessorFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<AccessorFilter>;
  OR?: InputMaybe<AccessorFilter>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  keys?: InputMaybe<Scalars['JSON']['input']>;
};

export enum AccessorKind {
  Image = 'IMAGE',
  Label = 'LABEL'
}

/** A view recording when and by whom an image region was acquired at the microscope. Use it to trace an image back to its acquisition session and operator. */
export type AcquisitionView = View & {
  __typename?: 'AcquisitionView';
  /** The accessor */
  accessor: Array<Scalars['String']['output']>;
  acquiredAt?: Maybe<Scalars['DateTime']['output']>;
  cMax?: Maybe<Scalars['Int']['output']>;
  cMin?: Maybe<Scalars['Int']['output']>;
  /** All views of this image */
  congruentViews: Array<View>;
  description?: Maybe<Scalars['String']['output']>;
  id: Scalars['ID']['output'];
  image: Image;
  isGlobal: Scalars['Boolean']['output'];
  operator?: Maybe<User>;
  tMax?: Maybe<Scalars['Int']['output']>;
  tMin?: Maybe<Scalars['Int']['output']>;
  xMax?: Maybe<Scalars['Int']['output']>;
  xMin?: Maybe<Scalars['Int']['output']>;
  yMax?: Maybe<Scalars['Int']['output']>;
  yMin?: Maybe<Scalars['Int']['output']>;
  zMax?: Maybe<Scalars['Int']['output']>;
  zMin?: Maybe<Scalars['Int']['output']>;
};


/** A view recording when and by whom an image region was acquired at the microscope. Use it to trace an image back to its acquisition session and operator. */
export type AcquisitionViewCongruentViewsArgs = {
  filters?: InputMaybe<ViewFilter>;
  types?: InputMaybe<Array<ViewKind>>;
};

/** A general affine map, given as an M x (N+1) matrix with rows outermost */
export type AffineTransformation = Transformation & {
  __typename?: 'AffineTransformation';
  /** The affine matrix, M x (N+1), rows outermost. The last column is the translation */
  affine: Array<Array<Scalars['Float']['output']>>;
  createdAt: Scalars['DateTime']['output'];
  creator?: Maybe<User>;
  id: Scalars['ID']['output'];
  input?: Maybe<CoordinateSystem>;
  /** The names of the input axes this edge's parameters are ordered by. `scale`, `translation` and the columns of `affine` follow this order -- which is the input system's axis order, NOT the reading layer's axis names, and the two differ often enough that indexing the arrays against them silently misplaces them. A BY_DIMENSION edge names only the subset of axes it acts on; the axes it does not name are the ones it leaves untouched */
  inputAxes: Array<Scalars['String']['output']>;
  kind: TransformKind;
  name?: Maybe<Scalars['String']['output']>;
  output?: Maybe<CoordinateSystem>;
  /** The names of the output axes this edge produces. For a rank-changing BY_DIMENSION edge (placing a (c,y,x) dataset into a (t,z,y,x) world) this is the subset it maps onto; the world's other axes are untouched */
  outputAxes: Array<Scalars['String']['output']>;
  /** Provenance entries for this edge: who authored it, and every refinement since. A refinement rewrites the edge in place and bumps `version`, so this audit trail is where the placement's earlier states live */
  provenanceEntries: Array<ProvenanceEntry>;
  /** How much this map is actually known: VALIDATED for a map the server derived (or one someone checked), INFERRED for numbers read from metadata, MANUAL for an authored registration, UNKNOWN for one the server assumed. A layer's validity is the weakest edge on its path to world */
  validity: PlacementValidity;
  /** (derivation edges) What the operation this edge records did to the *values*, orthogonal to `kind`: IDENTICAL (a crop -- statistics transfer), TRANSFORMED (a deconvolution -- same quantity, new numbers), CATEGORIZED (a threshold -- values became labels, and a bootstrapped scene renders the data as a label map). Null when unstated, and never present on a registration -- values do not cross a claim between spaces */
  valueRelation?: Maybe<ValueRelation>;
  version: Scalars['Int']['output'];
};


/** A general affine map, given as an M x (N+1) matrix with rows outermost */
export type AffineTransformationProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

/** A view placing an image region in physical space: a 4x4 affine matrix maps pixel coordinates onto a stage, encoding position and pixel size. */
export type AffineTransformationView = View & {
  __typename?: 'AffineTransformationView';
  /** The accessor */
  accessor: Array<Scalars['String']['output']>;
  affineMatrix: Scalars['FourByFourMatrix']['output'];
  cMax?: Maybe<Scalars['Int']['output']>;
  cMin?: Maybe<Scalars['Int']['output']>;
  /** All views of this image */
  congruentViews: Array<View>;
  id: Scalars['ID']['output'];
  image: Image;
  isGlobal: Scalars['Boolean']['output'];
  isotropic: Scalars['Boolean']['output'];
  pixelSize: Array<Scalars['Length']['output']>;
  pixelSizeX: Scalars['Length']['output'];
  pixelSizeY: Scalars['Length']['output'];
  pixelSizeZ: Scalars['Length']['output'];
  position: Array<Scalars['Length']['output']>;
  stage: Stage;
  tMax?: Maybe<Scalars['Int']['output']>;
  tMin?: Maybe<Scalars['Int']['output']>;
  xMax?: Maybe<Scalars['Int']['output']>;
  xMin?: Maybe<Scalars['Int']['output']>;
  yMax?: Maybe<Scalars['Int']['output']>;
  yMin?: Maybe<Scalars['Int']['output']>;
  zMax?: Maybe<Scalars['Int']['output']>;
  zMin?: Maybe<Scalars['Int']['output']>;
};


/** A view placing an image region in physical space: a 4x4 affine matrix maps pixel coordinates onto a stage, encoding position and pixel size. */
export type AffineTransformationViewCongruentViewsArgs = {
  filters?: InputMaybe<ViewFilter>;
  types?: InputMaybe<Array<ViewKind>>;
};

export type AffineTransformationViewEvent = {
  __typename?: 'AffineTransformationViewEvent';
  create?: Maybe<AffineTransformationView>;
  delete?: Maybe<Scalars['ID']['output']>;
  update?: Maybe<AffineTransformationView>;
};

export type AffineTransformationViewFilter = {
  AND?: InputMaybe<AffineTransformationViewFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<AffineTransformationViewFilter>;
  OR?: InputMaybe<AffineTransformationViewFilter>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  /** Filter by the image this view belongs to */
  image?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by a list of images this view belongs to */
  images?: InputMaybe<Array<Scalars['ID']['input']>>;
  isGlobal?: InputMaybe<Scalars['Boolean']['input']>;
  /** Search by the name of the image this view belongs to */
  search?: InputMaybe<Scalars['String']['input']>;
  stage?: InputMaybe<StageFilter>;
};

/** Input for creating an affine transformation view on an existing image, referenced by ID */
export type AffineTransformationViewInput = {
  /** The 4x4 affine matrix mapping image coordinates to stage coordinates */
  affineMatrix: Scalars['FourByFourMatrix']['input'];
  /** The maximum c (channel) coordinate of the view */
  cMax?: InputMaybe<Scalars['Int']['input']>;
  /** The minimum c (channel) coordinate of the view */
  cMin?: InputMaybe<Scalars['Int']['input']>;
  /** The collection this view belongs to */
  collection?: InputMaybe<Scalars['ID']['input']>;
  /** The ID of the image this view is for */
  image: Scalars['ID']['input'];
  /** The ID of the stage this transformation maps the image onto */
  stage?: InputMaybe<Scalars['ID']['input']>;
  /** The maximum t coordinate of the view */
  tMax?: InputMaybe<Scalars['Int']['input']>;
  /** The minimum t coordinate of the view */
  tMin?: InputMaybe<Scalars['Int']['input']>;
  /** The maximum x coordinate of the view */
  xMax?: InputMaybe<Scalars['Int']['input']>;
  /** The minimum x coordinate of the view */
  xMin?: InputMaybe<Scalars['Int']['input']>;
  /** The maximum y coordinate of the view */
  yMax?: InputMaybe<Scalars['Int']['input']>;
  /** The minimum y coordinate of the view */
  yMin?: InputMaybe<Scalars['Int']['input']>;
  /** The maximum z coordinate of the view */
  zMax?: InputMaybe<Scalars['Int']['input']>;
  /** The minimum z coordinate of the view */
  zMin?: InputMaybe<Scalars['Int']['input']>;
};

/** A named camera tour of a scene: the poses a viewer pans through, in order. A view artifact -- it cascades with the scene, no placement walk crosses it, and refining a registration moves the data but never the camera */
export type Animation = {
  __typename?: 'Animation';
  createdAt: Scalars['DateTime']['output'];
  /** The task this tour was created through, if any */
  createdThrough?: Maybe<Task>;
  /** The assigner of the creating task, if any */
  createdThroughBy?: Maybe<User>;
  creator?: Maybe<User>;
  description?: Maybe<Scalars['String']['output']>;
  id: Scalars['ID']['output'];
  name: Scalars['String']['output'];
  /** The scene this tour flies through */
  scene: Scene;
  /** The poses the viewer pans through, in tour order */
  waypoints: Array<AnimationWaypoint>;
};


/** A named camera tour of a scene: the poses a viewer pans through, in order. A view artifact -- it cascades with the scene, no placement walk crosses it, and refining a registration moves the data but never the camera */
export type AnimationWaypointsArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type AnimationFilter = {
  AND?: InputMaybe<AnimationFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<AnimationFilter>;
  OR?: InputMaybe<AnimationFilter>;
  /** Filter by the sub of the user that assigned the creating task */
  assignedBy?: InputMaybe<Scalars['ID']['input']>;
  /** Filter for items created after this datetime */
  createdAfter?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter for items created before this datetime */
  createdBefore?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter by the database ID of the task the item was created through (the `createdThrough { id }` field) */
  createdThrough?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the database ID of the user that assigned the creating task (the `createdThroughBy { id }` field) */
  createdThroughBy?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the rekuest task id the item was created through */
  createdThroughTask?: InputMaybe<Scalars['String']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter by the creator's subject ID */
  owner?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the scene this tour flies through */
  scene?: InputMaybe<Scalars['ID']['input']>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
};

export type AnimationOrder =
  { createdAt: Ordering; id?: never; name?: never; }
  |  { createdAt?: never; id: Ordering; name?: never; }
  |  { createdAt?: never; id?: never; name: Ordering; };

/** One camera pose in a tour, and how the viewer travels to it */
export type AnimationWaypoint = {
  __typename?: 'AnimationWaypoint';
  /** The tour this pose belongs to */
  animation: Animation;
  /** Where the camera is: a position keyed by the world's axis names, plus the flat and volumetric views of it */
  camera: CameraState;
  /** How long the viewer takes to travel TO this pose, in milliseconds. Ignored for the first pose, which is where the tour starts */
  durationMs: Scalars['Int']['output'];
  /** How the viewer eases the camera along that travel */
  easing: Easing;
  id: Scalars['ID']['output'];
  /** What this stop shows, e.g. 'the nucleus' */
  name: Scalars['String']['output'];
  /** The pose's index in the tour. Written by enumeration when the tour is authored, so it always runs 0, 1, 2 ... with no gaps */
  order: Scalars['Int']['output'];
};

/** One camera pose in a tour, and how the viewer travels to it. Its position in the tour is its position in the `waypoints` list -- there is no order field to pass */
export type AnimationWaypointInput = {
  /** Where the camera is at this stop */
  camera: CameraStateInput;
  /** How long the viewer takes to travel to this stop, in milliseconds */
  durationMs?: InputMaybe<Scalars['Int']['input']>;
  /** How the viewer eases the camera along that travel */
  easing?: InputMaybe<Easing>;
  /** What this stop shows */
  name?: InputMaybe<Scalars['String']['input']>;
};

/** A human-drawn shape in an annotation collection's coordinate system. It belongs to the collection, not to a scene: delete the scene and the annotation survives */
export type Annotation = {
  __typename?: 'Annotation';
  /** The collection this annotation belongs to; its vectors are expressed in the collection's own coordinate system */
  collection: AnnotationCollection;
  /** The coordinate system this annotation's vectors are expressed in: its collection's own system */
  coordinateSystem?: Maybe<CoordinateSystem>;
  /** The discrete coordinates this annotation is pinned to. A coordinate the annotation does not pin is one it spans */
  coordinates: Array<Coordinate>;
  createdWithTransforms: Scalars['Int']['output'];
  description?: Maybe<Scalars['String']['output']>;
  /** The fill color of the geometry, as RGBA, or null for no fill */
  fillColor?: Maybe<Array<Scalars['Int']['output']>>;
  /** Whether the geometry is filled with fill_color */
  filled: Scalars['Boolean']['output'];
  id: Scalars['UUID']['output'];
  /** The annotation's bounding box in the nearest intrinsic space, derived from every corner of its geometry (an affine-transformed box is not a box: min/max alone gives a strictly too-small answer under rotation or shear). Intrinsic, not world: world is scene-owned, and one collection can sit in two scenes under two registrations */
  intrinsicBbox?: Maybe<BoundingBox>;
  kind: RoiKind;
  name: Scalars['String']['output'];
  /** Provenance entries for this annotation */
  provenanceEntries: Array<ProvenanceEntry>;
  /** The stroke (outline) color of the geometry, as RGBA */
  strokeColor?: Maybe<Array<Scalars['Int']['output']>>;
  /** The stroke width of the geometry, in the drawing space's units */
  strokeWidth: Scalars['Float']['output'];
  vectors: Array<Array<Scalars['Float']['output']>>;
};


/** A human-drawn shape in an annotation collection's coordinate system. It belongs to the collection, not to a scene: delete the scene and the annotation survives */
export type AnnotationProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

/** A named set of human-drawn annotations, owning the coordinate system they are drawn in. The CRUD counterpart of a table dataset's machine-produced rows: shapes a person draws and edits, sharing one drawing space and one registration story */
export type AnnotationCollection = {
  __typename?: 'AnnotationCollection';
  /** The annotations in this collection */
  annotations: Array<Annotation>;
  /** The coordinate system the annotations' vectors are expressed in. The collection owns it; `derivedFrom` relates it to whatever the shapes are drawn over */
  coordinateSystem: CoordinateSystem;
  createdAt: Scalars['DateTime']['output'];
  creator?: Maybe<User>;
  /** The edge relating this collection's space to the space the shapes are drawn over -- an identity into a scene's world for a scene-minted collection, an identity into a dataset's system for one drawn over an image. Null for a freestanding collection */
  derivedFrom?: Maybe<Transformation>;
  description?: Maybe<Scalars['String']['output']>;
  id: Scalars['ID']['output'];
  name: Scalars['String']['output'];
  /** Provenance entries for this annotation collection */
  provenanceEntries: Array<ProvenanceEntry>;
  /** The scene this collection was minted for as its default drawing surface, or null for a freestanding or dataset-derived collection. Bookkeeping, not placement: the registration edge is what places it */
  scene?: Maybe<Scene>;
};


/** A named set of human-drawn annotations, owning the coordinate system they are drawn in. The CRUD counterpart of a table dataset's machine-produced rows: shapes a person draws and edits, sharing one drawing space and one registration story */
export type AnnotationCollectionAnnotationsArgs = {
  filters?: InputMaybe<AnnotationFilter>;
  ordering?: Array<AnnotationOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A named set of human-drawn annotations, owning the coordinate system they are drawn in. The CRUD counterpart of a table dataset's machine-produced rows: shapes a person draws and edits, sharing one drawing space and one registration story */
export type AnnotationCollectionProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type AnnotationCollectionFilter = {
  AND?: InputMaybe<AnnotationCollectionFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<AnnotationCollectionFilter>;
  OR?: InputMaybe<AnnotationCollectionFilter>;
  /** Filter by the coordinate system the annotations are drawn in (the collection's own) */
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  /** Filter for items created after this datetime */
  createdAfter?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter for items created before this datetime */
  createdBefore?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter by the dataset the shapes are drawn over, following the derivation edge */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter by the creator's subject ID */
  owner?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the scene this collection was minted for as its default drawing surface */
  scene?: InputMaybe<Scalars['ID']['input']>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
};

export type AnnotationCollectionOrder =
  { createdAt: Ordering; id?: never; name?: never; }
  |  { createdAt?: never; id: Ordering; name?: never; }
  |  { createdAt?: never; id?: never; name: Ordering; };

export type AnnotationFilter = {
  AND?: InputMaybe<AnnotationFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<AnnotationFilter>;
  OR?: InputMaybe<AnnotationFilter>;
  /** Filter by the collection this annotation belongs to */
  collection?: InputMaybe<Scalars['ID']['input']>;
  /** Filter to annotations whose intrinsic bounding box contains this point (GiST-backed). Only meaningful within one frame: pass `collection` or `coordinateSystem` alongside */
  containsPoint?: InputMaybe<Array<Scalars['Float']['input']>>;
  /** Filter by the coordinate system this annotation is drawn in (its collection's own) */
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the dataset the annotations are drawn over, following the collection's derivation edge */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  description?: InputMaybe<StrFilterLookup>;
  id?: InputMaybe<Scalars['UUID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  /** Filter to annotations whose intrinsic bounding box overlaps this box (GiST-backed). Only meaningful within one frame: pass `collection` or `coordinateSystem` alongside. A box of lower rank is zero-filled on the missing coordinates */
  intersects?: InputMaybe<BoundingBoxInput>;
  kind?: InputMaybe<RoiKindChoices>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter to annotations pinned to every one of these coordinates, e.g. [{name: 't', value: 3}]. GIN-backed containment on the stored coordinate dict; an annotation that spans a coordinate does not match a pin on it */
  pinnedTo?: InputMaybe<Array<CoordinateInput>>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
};

/** A layer that renders an annotation collection's drawn shapes (polygons, boxes, ellipses, lines, paths) in a scene. One layer per collection: per-shape styling lives on the annotations themselves. */
export type AnnotationLayer = Layer & {
  __typename?: 'AnnotationLayer';
  /** The annotation collection whose shapes this layer renders. Its own coordinate system is the layer's space */
  annotationCollection: AnnotationCollection;
  blending: Blending;
  id: Scalars['ID']['output'];
  kind: LayerKind;
  opacity: Scalars['Float']['output'];
  order: Scalars['Int']['output'];
  /** The path of transformation edges from this layer's source coordinate system to its scene's WORLD system. A layer belongs to exactly one scene, so this is the one 'to world' question with a single right answer -- the path uses the layer's dataset facts plus this scene's membership edges, never another scene's registration. Null when the layer is unregistered or has no source system; empty when the source already is the world system. The server returns the edges; composing them (inverting flagged steps) stays the client's job */
  pathToWorld?: Maybe<Array<PlacementStep>>;
  /** Whether this layer has a place in its scene's world, and if not, why not. A null `pathToWorld` means two different things -- nobody has registered this data yet, or its geometry did not survive the operation that produced it and it can never be placed -- and a client should not have to guess which. UNREGISTERED is a gap to close; UNMAPPABLE is a fact to badge. Derived, never stored */
  placement: PlacementState;
  /** How much this layer's placement is actually known: the weakest edge on its path to world. UNKNOWN while the path rests on an assumed edge (an uncalibrated bootstrap mirror, or none at all); MANUAL once someone authored the registration; VALIDATED once it was checked. Derived, never stored -- and distinct from a single edge's `validity`: this is the minimum over the whole path */
  placementValidity: PlacementValidity;
  scene: Scene;
  visible: Scalars['Boolean']['output'];
};

export type AnnotationOrder =
  { id: Ordering; name?: never; }
  |  { id?: never; name: Ordering; };

/** One shape of a bulk draw: the per-annotation subset of CreateAnnotationInput, without the collection/scene target */
export type AnnotationSpecInput = {
  coordinates?: InputMaybe<Array<CoordinateInput>>;
  description?: InputMaybe<Scalars['String']['input']>;
  fillColor?: InputMaybe<Array<Scalars['Int']['input']>>;
  filled?: InputMaybe<Scalars['Boolean']['input']>;
  kind: RoiKind;
  name?: InputMaybe<Scalars['String']['input']>;
  strokeColor?: InputMaybe<Array<Scalars['Int']['input']>>;
  strokeWidth?: InputMaybe<Scalars['Float']['input']>;
  vectors: Array<Scalars['ThreeDVector']['input']>;
};

/** Input for assigning object-level permissions to a user */
export type AssignUserPermissionInput = {
  /** The type identifier of the object, e.g. "@mikro/image" */
  identifier: Scalars['String']['input'];
  /** The primary key of the object to assign permissions on */
  object: Scalars['ID']['input'];
  /** The permissions to assign, e.g. ["view_image", "change_image"] */
  permissions: Array<Scalars['String']['input']>;
  /** The primary key of the user to assign permissions to */
  user: Scalars['ID']['input'];
};

/** An input for associating a set of items with another item, e.g. putting images into a dataset */
export type AssociateInput = {
  /** The ID of the target item */
  other: Scalars['ID']['input'];
  /** The IDs of the items to associate */
  selfs: Array<Scalars['ID']['input']>;
};

/** One executable answer to 'what is under this point?': map the point along `path` if the plan is not rooted where you probed, sample the field array, then look the value up in the table's parquet. Plans are discovered across the fact component -- probe a source image and the plans of the instance mask derived from it are found through the derivation edge -- but never through a registration: which claims compose is a scene's say-so, and this query has no scene. A plan takes no coordinate -- it is the same plan for every point, so fetch it once, cache it, and execute per hover locally with zero round-trips. attributePlans returns instructions, never attributes: anything that wants values runs the plan */
export type AttributePlan = {
  __typename?: 'AttributePlan';
  /** The FIELD edge this plan was built from. The plan's cache key is this edge's (id, version) together with every `path` step's transformation (id, version): the stores and columns of a table are written once, so a deleted or version-bumped edge -- the FIELD, or any step on the way to it -- is the only thing that can stale a cached plan */
  edge: FieldTransformation;
  /** The duckdb half: look the sampled value up in the parquet */
  lookup: LookupStep;
  /** The steps from the PROBED system to this plan's root (the FIELD edge's input system -- equal to `sample.system` when the mask's own pixels are the map). Empty when the plan is rooted where you probed. Compose in order, inverting the flagged steps, to map a probed-space point into the space `consumes` and `passthrough` are stated in -- the same contract as `pathToWorld`. The path crosses derivations, levels, lenses and calibrations, never a registration */
  path: Array<PlacementStep>;
  /** The zarr half: sample the field array at the (path-mapped) point */
  sample: SampleStep;
  /** The table the plan lands in: the home of the attributes, its columns and their `references` */
  table: TableDataset;
};

/** One named, typed dimension of a coordinate system. Its `order` is its index into the array shape */
export type Axis = {
  __typename?: 'Axis';
  description?: Maybe<Scalars['String']['output']>;
  id: Scalars['ID']['output'];
  longName?: Maybe<Scalars['String']['output']>;
  name: Scalars['String']['output'];
  order: Scalars['Int']['output'];
  type: AxisType;
  unit?: Maybe<Scalars['Unit']['output']>;
};

/** Input type for an axis anchor, which pins one axis to one discrete position */
export type AxisAnchorInput = {
  axis: Scalars['String']['input'];
  value: Scalars['Int']['input'];
};

export type AxisFilter = {
  AND?: InputMaybe<AxisFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<AxisFilter>;
  OR?: InputMaybe<AxisFilter>;
  /** Filter by the coordinate system this axis belongs to */
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  name?: InputMaybe<StrFilterLookup>;
  type?: InputMaybe<AxisTypeChoices>;
};

/** Input type for one structural axis of a dataset's pixel grid: its name and its semantic kind. Units and spacings do not belong here -- they are a calibration, a separate coordinate system plus one edge */
export type AxisInput = {
  description?: InputMaybe<Scalars['String']['input']>;
  longName?: InputMaybe<Scalars['String']['input']>;
  name: Scalars['String']['input'];
  type: AxisType;
};

/** The semantic kind of an axis. A system's axes must be ordered by type: time first, then channel and custom types, then space. */
export enum AxisType {
  /** A categorical channel axis: its coordinates index acquisitions, not positions. Never downsampled. */
  Channel = 'CHANNEL',
  /** The value axis of a coordinate-valued array: its positions enumerate the components of an absolute output position. This is what makes the array readable as the `field` of a FIELD edge. A scalar-valued field (a label mask, whose one value is an object id) carries no value axis at all -- absent means scalar, and scalar means COORDINATE. */
  Coordinate = 'COORDINATE',
  /** The value axis of a displacement-valued array: its positions enumerate the components of a per-point OFFSET, where COORDINATE enumerates absolute positions. Stating it here rather than on the edge is deliberate: it is a property of the array, and an array that says it twice can disagree with itself. */
  Displacement = 'DISPLACEMENT',
  /** An enumerating axis with no metric: an object id, a row number. It has no unit because there is nothing to measure — the distance between object 3 and object 4 means nothing. */
  Index = 'INDEX',
  /** A FLIM arrival-time bin. Continuous, so a pyramid may re-bin it, and a phasor may be taken over it. */
  Microtime = 'MICROTIME',
  /** A spatial axis. Unitless pixel indices in an INTRINSIC/ARRAY system; carries a physical length unit in a calibrated system. */
  Space = 'SPACE',
  /** A wavelength bin of a spectrally resolved acquisition. Continuous -- unlike a CHANNEL axis, whose coordinates index acquisitions rather than positions -- so a pyramid may re-bin it, and a phasor may be taken over it. */
  Spectrum = 'SPECTRUM',
  /** A time axis. Frame indices in an INTRINSIC/ARRAY system; carries a physical duration unit in a calibrated system. */
  Time = 'TIME'
}

export enum AxisTypeChoices {
  Channel = 'CHANNEL',
  Coordinate = 'COORDINATE',
  Displacement = 'DISPLACEMENT',
  Index = 'INDEX',
  Microtime = 'MICROTIME',
  Space = 'SPACE',
  Spectrum = 'SPECTRUM',
  Time = 'TIME'
}

