/** The connected component of the coordinate graph around one system: every coordinate system it relates to, and every top-level edge between them. Reachability is undirected -- an edge pointing *into* the system you started from (a calibration, say) relates to it just as much as one pointing out -- but every edge is returned in its true stored direction, so composing a path is still the client's job and still needs the inversions flagged */
export type CoordinateGraph = {
  __typename?: 'CoordinateGraph';
  /** The coordinate system the walk started from */
  root: CoordinateSystem;
  /** Every coordinate system reachable from the root, the root included, ordered by ID */
  systems: Array<CoordinateSystem>;
  /** Every top-level edge with both endpoints in `systems`, ordered by ID. The children of a SEQUENCE / BY_DIMENSION / BIJECTION wrapper are not listed here; they hang off their wrapper */
  transformations: Array<Transformation>;
};

/** A discrete coordinate an annotation is pinned to, e.g. a timepoint or a channel */
export type CoordinateInput = {
  name: Scalars['String']['input'];
  value: Scalars['Int']['input'];
};

/** A named coordinate space: a node in the transformation graph. Its axes are ordered, and that order is the order of the array's dimensions */
export type CoordinateSystem = {
  __typename?: 'CoordinateSystem';
  /** The system's axes, in array order (slowest-varying first). RFC-5 requires them ordered by type: time, then channel and custom types, then space */
  axes: Array<Axis>;
  createdAt: Scalars['DateTime']['output'];
  creator?: Maybe<User>;
  /** The wall-clock instant this system's time axis has its origin at: `wall_clock = epoch + t * unit`. A property of the space, not of any composition over it. Meaningful only for a calibrated system with a TIME axis (a scene's world, a shared hub); null when the clock is unanchored -- the time axis is still a perfectly composable relative coordinate */
  epoch?: Maybe<Scalars['DateTime']['output']>;
  id: Scalars['ID']['output'];
  /** Whether a scene may compose over this system as its world, i.e. whether `createSceneFromCoordinateSystem` will accept it. False for an ARRAY system (a pyramid level, a lens crop -- a slice *of* a space, not a space to compose in; its container's intrinsic system is the honest root one hop away) and for another scene's minted world (which cascades with its scene and would be deleted out from under the adopter) */
  isAdoptableWorld: Scalars['Boolean']['output'];
  /** Whether this is an ownerless shared space, built to be registered into. The one kind of system created bare (`createCoordinateSystem`), and the only adoptable world that can receive registrations -- a scene's own world is SHARED too, but it is scene-owned and cascades away with its scene */
  isHub: Scalars['Boolean']['output'];
  /** What this system denotes, derived from its owner: INTRINSIC for a container's own native space (a dataset's level-0 pixel grid, a mesh collection's vertex space, a table's coordinate-column space), ARRAY for a derived pixel grid (a pyramid level, a slicing lens), PHYSICAL for a calibration, SHARED for a space sources register into (a scene's world, an ownerless hub) */
  kind: CoordinateSystemKind;
  name: Scalars['String']['output'];
  /** The container this system belongs to and cascades with: the dataset whose pixel grid or calibration it is, the pyramid level or lens whose grid it is, the collection or table whose native space it is, or the scene the world was minted for. Null for a hub, which nobody owns -- `kind` tells you *what* a system denotes, this tells you *whose* it is */
  owner?: Maybe<CoordinateSystemOwner>;
  /** Provenance entries for this coordinate system: who created it, and every subsequent change */
  provenanceEntries: Array<ProvenanceEntry>;
  /** The scenes that compose over this system as their world. Non-empty only for a SHARED space (a world minted for one scene, or an ownerless hub): a hub lists every scene sharing it, and outlives each of them. The inverse of `Scene.worldCoordinateSystem` */
  scenes: Array<Scene>;
};


/** A named coordinate space: a node in the transformation graph. Its axes are ordered, and that order is the order of the array's dimensions */
export type CoordinateSystemAxesArgs = {
  filters?: InputMaybe<AxisFilter>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A named coordinate space: a node in the transformation graph. Its axes are ordered, and that order is the order of the array's dimensions */
export type CoordinateSystemProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A named coordinate space: a node in the transformation graph. Its axes are ordered, and that order is the order of the array's dimensions */
export type CoordinateSystemScenesArgs = {
  filters?: InputMaybe<SceneFilter>;
  ordering?: Array<SceneOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type CoordinateSystemFilter = {
  AND?: InputMaybe<CoordinateSystemFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<CoordinateSystemFilter>;
  OR?: InputMaybe<CoordinateSystemFilter>;
  /** Filter for items created after this datetime */
  createdAfter?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter for items created before this datetime */
  createdBefore?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter by the dataset this system belongs to directly: its INTRINSIC pixel grid or one of its PHYSICAL calibrations */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  /** Filter to ownerless shared spaces -- the hubs, the only systems that can receive registrations and be shared between scenes. Narrower than `kind: SHARED`, which also matches each scene's own minted world */
  isHub?: InputMaybe<Scalars['Boolean']['input']>;
  /** Filter by what the system denotes, derived from its owner: INTRINSIC (a container's own native space), ARRAY (a pyramid level's or lens' grid), PHYSICAL (a calibration), SHARED (a scene's world or an ownerless hub) */
  kind?: InputMaybe<CoordinateSystemKind>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter by the creator's subject ID */
  owner?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by a scene composing over this system -- its minted world or an adopted hub */
  scene?: InputMaybe<Scalars['ID']['input']>;
  /** Search by name (case-insensitive substring) */
  search?: InputMaybe<Scalars['String']['input']>;
};

/** What a coordinate system denotes, derived entirely from which container owns it: a container's own native space, a derived pixel grid, a calibrated interpretation, or a space shared between sources. */
export enum CoordinateSystemKind {
  /** A derived pixel grid: the voxel index space of a non-level-0 pyramid level or of a slicing lens. Its axes are unitless indices, and an edge maps it into the dataset's intrinsic grid. */
  Array = 'ARRAY',
  /** The native space of its container: a dataset's level-0 pixel grid, the space a mesh collection's vertices are expressed in, or a table dataset's coordinate-column space. Always defined, never revised — recalibrating never moves it — which is why geometry anchors to it. What the coordinates mean is on the axes (semantic type, unit or unitless), and which container it is, on the owner. */
  Intrinsic = 'INTRINSIC',
  /** A calibrated physical space derived from metadata (pixel size, stage pose, ...). Its axes carry the units; a single transformation edge maps the dataset's intrinsic pixels into it. A dataset can have zero or many. */
  Physical = 'PHYSICAL',
  /** A space sources are registered into rather than owned by any of them: a scene's world (scene-owned, cascades with it) or an ownerless hub such as an anatomical atlas (standing, shared across scenes). The scene link tells the two apart. */
  Shared = 'SHARED'
}

export type CoordinateSystemOrder =
  { createdAt: Ordering; id?: never; name?: never; }
  |  { createdAt?: never; id: Ordering; name?: never; }
  |  { createdAt?: never; id?: never; name: Ordering; };

/** The container that owns a coordinate system and that it cascades with. A hub has none */
export type CoordinateSystemOwner = ADataset | DataArray | Lens | MeshCollection | Scene | TableDataset;

/** Input type for creating an array dataset. Its axes are structural (name and kind); physical units, if known, arrive as an optional calibration */
export type CreateADatasetInput = {
  anchors?: InputMaybe<Array<CoordinateAnchorInput>>;
  axes: Array<AxisInput>;
  bootstrapScene?: InputMaybe<BootstrapSceneInput>;
  calibration?: InputMaybe<CalibrationSpecInput>;
  data: Scalars['ArrayLike']['input'];
  derivedFrom?: InputMaybe<Array<DerivedFromInput>>;
  name: Scalars['String']['input'];
  scales: Array<ScaleInput>;
};

/** Input for creating a named camera tour of a scene. The waypoints are given in tour order and that order is what is stored -- a tour is authored as a whole, never a stop at a time */
export type CreateAnimationInput = {
  /** What the tour shows */
  description?: InputMaybe<Scalars['String']['input']>;
  /** The name of the tour */
  name: Scalars['String']['input'];
  /** The ID of the scene this tour flies through */
  scene: Scalars['ID']['input'];
  /** The poses the viewer pans through, in tour order */
  waypoints: Array<AnimationWaypointInput>;
};

/** Input for creating an annotation collection. The collection gets a coordinate system of its own, and an edge relates it to the space the shapes are drawn over */
export type CreateAnnotationCollectionInput = {
  axes?: InputMaybe<Array<AxisInput>>;
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  derivedFrom?: InputMaybe<DerivationInput>;
  description?: InputMaybe<Scalars['String']['input']>;
  name: Scalars['String']['input'];
};

/** Input for drawing an annotation. Provide exactly one of `collection` (append to it) or `scene` (draw on the scene: its annotation collection is found, or minted on first use together with its coordinate system, its registration into the world, and its layer) */
export type CreateAnnotationInput = {
  collection?: InputMaybe<Scalars['ID']['input']>;
  coordinates?: InputMaybe<Array<CoordinateInput>>;
  description?: InputMaybe<Scalars['String']['input']>;
  fillColor?: InputMaybe<Array<Scalars['Int']['input']>>;
  filled?: InputMaybe<Scalars['Boolean']['input']>;
  kind: RoiKind;
  name?: InputMaybe<Scalars['String']['input']>;
  scene?: InputMaybe<Scalars['ID']['input']>;
  strokeColor?: InputMaybe<Array<Scalars['Int']['input']>>;
  strokeWidth?: InputMaybe<Scalars['Float']['input']>;
  vectors: Array<Scalars['ThreeDVector']['input']>;
};

/** Create a layer that renders an annotation collection's drawn shapes in a scene. The collection's own coordinate system is the layer's space, so it must already have a path to the scene's world */
export type CreateAnnotationLayerInput = {
  annotationCollection: Scalars['ID']['input'];
  blending?: InputMaybe<Blending>;
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Input for drawing many annotations in one call. Provide exactly one of `collection` or `scene` (same semantics as createAnnotation); the transform chain and version resolve once for the whole batch */
export type CreateAnnotationsInput = {
  annotations: Array<AnnotationSpecInput>;
  collection?: InputMaybe<Scalars['ID']['input']>;
  scene?: InputMaybe<Scalars['ID']['input']>;
};

/** Input for calibrating a dataset: creates a PHYSICAL coordinate system (axes carrying the units) and the single edge mapping the dataset's intrinsic pixels into it */
export type CreateCalibrationInput = {
  affine?: InputMaybe<Array<Array<Scalars['Float']['input']>>>;
  axes: Array<CalibratedAxisInput>;
  /** The ID of the dataset to calibrate */
  dataset: Scalars['ID']['input'];
  name?: Scalars['String']['input'];
  scale?: InputMaybe<Array<Scalars['Float']['input']>>;
  translation?: InputMaybe<Array<Scalars['Float']['input']>>;
};

/** Create a hub coordinate system -- a SHARED reference space with no owner, e.g. an atlas -- and, in the same call, author the edges registering any number of sources (datasets, table datasets, mesh collections, coordinate systems) into it. Every other system is owned by a container and created with it, so a hub is the only system created directly. createSceneFromCoordinateSystem later mirrors the hub into a scene and materializes those sources as layers */
export type CreateCoordinateSystemInput = {
  axes: Array<CalibratedAxisInput>;
  epoch?: InputMaybe<Scalars['DateTime']['input']>;
  name: Scalars['String']['input'];
  registrations?: Array<RegistrationPathInput>;
};

/** Input for creating a new dataset to organize images and files */
export type CreateDatasetInput = {
  /** The name of the dataset */
  name: Scalars['String']['input'];
  /** The ID of the parent dataset to nest this dataset under */
  parent?: InputMaybe<Scalars['ID']['input']>;
};

/** Create a single-channel intensity layer rendered through a colormap (e.g. a fluorescence channel) */
export type CreateIntensityLayerInput = {
  blending?: InputMaybe<Blending>;
  climMax?: InputMaybe<Scalars['Float']['input']>;
  climMin?: InputMaybe<Scalars['Float']['input']>;
  colormap?: InputMaybe<ColorMap>;
  gamma?: InputMaybe<Scalars['Float']['input']>;
  intensityAxis?: InputMaybe<Scalars['String']['input']>;
  intensityIndex?: InputMaybe<Scalars['Int']['input']>;
  lens: Scalars['ID']['input'];
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Create a label layer that renders an instance / segmentation map, mapping discrete integer labels to distinct colors */
export type CreateLabelLayerInput = {
  intensityAxis?: InputMaybe<Scalars['String']['input']>;
  intensityIndex?: InputMaybe<Scalars['Int']['input']>;
  lens: Scalars['ID']['input'];
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Input type for creating an image from an array-like object */
export type CreateLayerInput = {
  blending?: InputMaybe<Blending>;
  lens: Scalars['ID']['input'];
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  renderGraph: LayerRenderGraphInput;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Input type for creating an image from an array-like object */
export type CreateLensInput = {
  dataset: Scalars['ID']['input'];
  slices: Array<SliceInput>;
};

/** Input for registering an immutable, versioned mesh collection. The collection gets a coordinate system of its own, and an edge relates it to the space the meshes were extracted from */
export type CreateMeshCollectionInput = {
  axes?: InputMaybe<Array<AxisInput>>;
  catalog: Scalars['ParquetLike']['input'];
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  derivedFrom?: InputMaybe<DerivationInput>;
  encoding?: InputMaybe<Scalars['Any']['input']>;
  geometry?: InputMaybe<Array<Scalars['ParquetLike']['input']>>;
  grid?: InputMaybe<Scalars['Any']['input']>;
  provenanceMetadata?: InputMaybe<Scalars['Any']['input']>;
  specVersion: Scalars['String']['input'];
  version: Scalars['String']['input'];
};

/** Create a layer that renders a mesh collection (surface reconstructions / isosurfaces) in a scene. The collection's own coordinate system is the layer's space, so it must already have a path to the scene's world */
export type CreateMeshLayerInput = {
  blending?: InputMaybe<Blending>;
  materialColor?: InputMaybe<Array<Scalars['Int']['input']>>;
  meshCollection: Scalars['ID']['input'];
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
  wireframe?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Attach an instrument-response correction to a dataset, taking a raw phasor to a calibrated one. Measured once per detector from a reference acquisition. Its absence is legitimate: an uncalibrated phasor still renders, its hue is just not traceable to an absolute lifetime */
export type CreatePhasorCalibrationInput = {
  /** The axis the correction applies to */
  axis: Scalars['String']['input'];
  /** The coordinates the correction is pinned to */
  axisAnchors?: InputMaybe<Array<AxisAnchorInput>>;
  /** The ID of the dataset the correction applies to */
  dataset: Scalars['ID']['input'];
  /** The harmonic the correction applies at */
  harmonic?: InputMaybe<Scalars['Int']['input']>;
  /** The modulation correction */
  modulationFactor?: InputMaybe<Scalars['Float']['input']>;
  /** The phase correction in radians */
  phaseOffset?: InputMaybe<Scalars['Float']['input']>;
  /** What the correction was measured against */
  reference?: InputMaybe<Scalars['String']['input']>;
};

/** Attach a phasor distribution to a dataset: the 2D (g, s) density of a phasor taken over one axis at one harmonic. Computed after ingest by a task that reads the cube; recomputing at the same harmonic replaces it, while a second harmonic lands beside the first */
export type CreatePhasorHistogramInput = {
  /** The axis the phasor was taken over */
  axis: Scalars['String']['input'];
  /** The coordinates the distribution is pinned to */
  axisAnchors?: InputMaybe<Array<AxisAnchorInput>>;
  /** The resolution of the square (g, s) density grid */
  bins?: InputMaybe<Scalars['Int']['input']>;
  calibrated?: InputMaybe<Scalars['Boolean']['input']>;
  /** The flattened bins x bins density */
  counts: Array<Scalars['Float']['input']>;
  /** The ID of the dataset the phasor was computed from */
  dataset: Scalars['ID']['input'];
  gMax?: InputMaybe<Scalars['Float']['input']>;
  gMin?: InputMaybe<Scalars['Float']['input']>;
  /** The harmonic the phasor was taken at */
  harmonic?: InputMaybe<Scalars['Int']['input']>;
  profile?: InputMaybe<Array<Scalars['Float']['input']>>;
  sMax?: InputMaybe<Scalars['Float']['input']>;
  sMin?: InputMaybe<Scalars['Float']['input']>;
  total?: InputMaybe<Scalars['Int']['input']>;
};

/** Create a layer that reduces one axis of a lens to a phasor and colors each pixel by it -- a lifetime overlay over a FLIM cube, or a spectral one over a hyperspectral cube */
export type CreatePhasorLayerInput = {
  blending?: InputMaybe<Blending>;
  harmonic?: InputMaybe<Scalars['Int']['input']>;
  intensityAxis?: InputMaybe<Scalars['String']['input']>;
  intensityIndex?: InputMaybe<Scalars['Int']['input']>;
  lens: Scalars['ID']['input'];
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  phasorAxis?: InputMaybe<Scalars['String']['input']>;
  scene: Scalars['ID']['input'];
  transfer?: InputMaybe<PhasorTransferInput>;
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Create a layer that renders a point cloud (e.g. SMLM localisations, centroids) from a table dataset */
export type CreatePointLayerInput = {
  blending?: InputMaybe<Blending>;
  colorColumn?: InputMaybe<Scalars['String']['input']>;
  colormap?: InputMaybe<ColorMap>;
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  pointSize?: InputMaybe<Scalars['Float']['input']>;
  scene: Scalars['ID']['input'];
  sizeColumn?: InputMaybe<Scalars['String']['input']>;
  tableDataset: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Input for creating an RGB render context for an image */
export type CreateRgbContextInput = {
  /** The channel the context renders */
  c?: InputMaybe<Scalars['Int']['input']>;
  /** The ID of the image this RGB context renders */
  image: Scalars['ID']['input'];
  /** The name of the RGB context */
  name?: InputMaybe<Scalars['String']['input']>;
  /** The timepoint the context renders */
  t?: InputMaybe<Scalars['Int']['input']>;
  /** The ID of an uploaded media store to use as the thumbnail snapshot */
  thumbnail?: InputMaybe<Scalars['ID']['input']>;
  /** The RGB views (channel rendering settings) to attach to the context */
  views?: InputMaybe<Array<PartialRgbViewInput>>;
  /** The z plane the context renders */
  z?: InputMaybe<Scalars['Int']['input']>;
};

/** Create a layer that composites three channels of a lens as red, green and blue */
export type CreateRgbLayerInput = {
  blueIndex?: InputMaybe<Scalars['Int']['input']>;
  climMax?: InputMaybe<Scalars['Float']['input']>;
  climMin?: InputMaybe<Scalars['Float']['input']>;
  greenIndex?: InputMaybe<Scalars['Int']['input']>;
  intensityAxis?: InputMaybe<Scalars['String']['input']>;
  lens: Scalars['ID']['input'];
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  redIndex?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Bootstrap a renderable scene over an existing coordinate system. Over a hub (an ownerless SHARED space) the sources already registered into it become layers, up to the policy's nchildren -- each source's path to world is the one registration createCoordinateSystem authored. Over an owned system (a dataset's INTRINSIC pixels, a PHYSICAL calibration, a collection's space) the container's own data becomes the layer: it is in its own space by construction, so no edge exists or is authored. Rerunning makes another scene over the same space, which outlives them all */
export type CreateSceneFromCoordinateSystemInput = {
  coordinateSystem: Scalars['ID']['input'];
  name?: InputMaybe<Scalars['String']['input']>;
  policy?: ScenePolicyInput;
};

/** Input for bootstrapping a renderable scene for a dataset: a world mirroring its calibration, a full lens, and one default image layer. Sugar over createScene + createLens + a layer mutation -- everything it creates is ordinary and separately editable */
export type CreateSceneFromDatasetInput = {
  dataset: Scalars['ID']['input'];
  kind?: InputMaybe<BootstrapLayerKind>;
  name?: InputMaybe<Scalars['String']['input']>;
};

/** Input type for creating a scene over a world coordinate system: an adopted existing system (a hub, a dataset's intrinsic grid, a calibration), or one minted for the scene */
export type CreateSceneInput = {
  axes?: InputMaybe<Array<CalibratedAxisInput>>;
  backgroundColor?: InputMaybe<Array<Scalars['Float']['input']>>;
  blending?: InputMaybe<Blending>;
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  epoch?: InputMaybe<Scalars['DateTime']['input']>;
  name: Scalars['String']['input'];
  preferredView?: InputMaybe<PreferredView>;
};

/** Input for creating a table dataset from a Parquet store. Its coordinate columns become the axes of a coordinate system it owns; declare no coordinate columns for a pure measurement table (its rows enumerate objects and its lineage edge is UNMAPPABLE) */
export type CreateTableDatasetInput = {
  columns?: Array<TableColumnInput>;
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  data: Scalars['ParquetLike']['input'];
  derivedFrom?: InputMaybe<DerivationInput>;
  description?: InputMaybe<Scalars['String']['input']>;
  name: Scalars['String']['input'];
  validateSchema?: Scalars['Boolean']['input'];
};

/** Create a layer that renders trajectories (e.g. particle/cell tracks) from a table dataset, grouped by its TRACK_ID column */
export type CreateTrackLayerInput = {
  blending?: InputMaybe<Blending>;
  colorByColumn?: InputMaybe<Scalars['String']['input']>;
  colormap?: InputMaybe<ColorMap>;
  lineWidth?: InputMaybe<Scalars['Float']['input']>;
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  tableDataset: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** Input for creating one edge of the coordinate graph, mapping an input coordinate system to an output one */
export type CreateTransformationInput = {
  affine?: InputMaybe<Array<Array<Scalars['Float']['input']>>>;
  field?: InputMaybe<Scalars['ID']['input']>;
  input: Scalars['ID']['input'];
  inputAxes?: InputMaybe<Array<Scalars['String']['input']>>;
  kind: TransformKind;
  name?: InputMaybe<Scalars['String']['input']>;
  output: Scalars['ID']['input'];
  outputAxes?: InputMaybe<Array<Scalars['String']['input']>>;
  reason?: InputMaybe<Scalars['String']['input']>;
  scale?: InputMaybe<Array<Scalars['Float']['input']>>;
  translation?: InputMaybe<Array<Scalars['Float']['input']>>;
  validity?: InputMaybe<PlacementValidity>;
  valueRelation?: InputMaybe<ValueRelation>;
};

/** Create a single-channel layer rendered as a 3D volume projection (MIP / attenuated-MIP / volume / isosurface) over its z-axis */
export type CreateVolumeLayerInput = {
  blending?: InputMaybe<Blending>;
  climMax?: InputMaybe<Scalars['Float']['input']>;
  climMin?: InputMaybe<Scalars['Float']['input']>;
  colormap?: InputMaybe<ColorMap>;
  gamma?: InputMaybe<Scalars['Float']['input']>;
  intensityAxis?: InputMaybe<Scalars['String']['input']>;
  intensityIndex?: InputMaybe<Scalars['Int']['input']>;
  lens: Scalars['ID']['input'];
  mode?: InputMaybe<ProjectionMode>;
  opacity?: InputMaybe<Scalars['Float']['input']>;
  order?: InputMaybe<Scalars['Int']['input']>;
  scene: Scalars['ID']['input'];
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** One level of a dataset's resolution pyramid: a zarr-backed array, with its own voxel-index coordinate system and a stored edge into the dataset's intrinsic space */
export type DataArray = {
  __typename?: 'DataArray';
  chunkShape: Array<Scalars['Int']['output']>;
  /** The coordinate system this level's voxels live in. Level 0 owns none: the dataset's INTRINSIC system IS the level-0 pixel grid, so this resolves to it. Higher levels own an ARRAY (voxel index) system */
  coordinateSystem?: Maybe<CoordinateSystem>;
  id: Scalars['ID']['output'];
  level: Scalars['Int']['output'];
  shape: Array<Scalars['Int']['output']>;
  store: ZarrStore;
  /** The edge from this level's voxel space into the dataset's intrinsic space. Its scale is absolute -- derived from the actual shapes, not from a nominal 2**level -- so a pyramid whose axes do not halve cleanly is described correctly. Null for level 0: its space IS the intrinsic space, and there is nothing to map */
  toParent?: Maybe<Transformation>;
};

export type DataArrayFilter = {
  AND?: InputMaybe<DataArrayFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<DataArrayFilter>;
  OR?: InputMaybe<DataArrayFilter>;
  /** Filter by the dataset this array belongs to */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  level?: InputMaybe<IntFilterLookup>;
};

export type DataArrayOrder =
  { id: Ordering; level?: never; }
  |  { id?: never; level: Ordering; };

/** A dataset is a collection of images and files. It mimics the concept of a folder in a file system and is the top-level container for organising data in mikro. */
export type Dataset = {
  __typename?: 'Dataset';
  children: Array<Dataset>;
  createdAt: Scalars['DateTime']['output'];
  /** The task this dataset was created through, if any */
  createdThrough?: Maybe<Task>;
  /** The assigner of the creating task, if any */
  createdThroughBy?: Maybe<User>;
  creator?: Maybe<User>;
  description?: Maybe<Scalars['String']['output']>;
  files: Array<File>;
  id: Scalars['ID']['output'];
  images: Array<Image>;
  isDefault: Scalars['Boolean']['output'];
  name: Scalars['String']['output'];
  parent?: Maybe<Dataset>;
  pinned: Scalars['Boolean']['output'];
  /** Provenance entries for this dataset */
  provenanceEntries: Array<ProvenanceEntry>;
  tags: Array<Scalars['String']['output']>;
};


/** A dataset is a collection of images and files. It mimics the concept of a folder in a file system and is the top-level container for organising data in mikro. */
export type DatasetChildrenArgs = {
  filters?: InputMaybe<DatasetFilter>;
  ordering?: Array<DatasetOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A dataset is a collection of images and files. It mimics the concept of a folder in a file system and is the top-level container for organising data in mikro. */
export type DatasetFilesArgs = {
  filters?: InputMaybe<FileFilter>;
  ordering?: Array<FileOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A dataset is a collection of images and files. It mimics the concept of a folder in a file system and is the top-level container for organising data in mikro. */
export type DatasetImagesArgs = {
  filters?: InputMaybe<ImageFilter>;
  ordering?: Array<ImageOrder>;
  pagination?: InputMaybe<OffsetPaginationInput>;
};


/** A dataset is a collection of images and files. It mimics the concept of a folder in a file system and is the top-level container for organising data in mikro. */
export type DatasetProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

export type DatasetChildrenFilter = {
  search?: InputMaybe<Scalars['String']['input']>;
  showChildren?: InputMaybe<Scalars['Boolean']['input']>;
};

export type DatasetFilter = {
  AND?: InputMaybe<DatasetFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<DatasetFilter>;
  OR?: InputMaybe<DatasetFilter>;
  /** Filter by the sub of the user that assigned the creating task */
  assignedBy?: InputMaybe<Scalars['ID']['input']>;
  /** Filter for items created after this datetime */
  createdAfter?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter for items created before this datetime */
  createdBefore?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter by the database ID of the task the item was created through (the `createdThrough { id }` field) */
  createdThrough?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the database ID of the user that assigned the creating task (the `createdThroughBy { id }` field) */
  createdThroughBy?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the rekuest task id the item was created through */
  createdThroughTask?: InputMaybe<Scalars['String']['input']>;
  description?: InputMaybe<StrFilterLookup>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  isDefault?: InputMaybe<Scalars['Boolean']['input']>;
  name?: InputMaybe<StrFilterLookup>;
  /** Filter by the creator's subject ID */
  owner?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the parent dataset (list the children of a dataset) */
  parent?: InputMaybe<Scalars['ID']['input']>;
  /** Filter for datasets with (true) or without (false) a parent */
  parentless?: InputMaybe<Scalars['Boolean']['input']>;
  /** Filter by whether the current user has pinned the item */
  pinned?: InputMaybe<Scalars['Boolean']['input']>;
  /** Search by name (full-text search) */
  search?: InputMaybe<Scalars['String']['input']>;
  /** Filter by tag names */
  tags?: InputMaybe<Array<Scalars['String']['input']>>;
};

export type DatasetImageFile = Dataset | File | Image;

export type DatasetOrder =
  { createdAt: Ordering; id?: never; name?: never; }
  |  { createdAt?: never; id: Ordering; name?: never; }
  |  { createdAt?: never; id?: never; name: Ordering; };

