/** A layer placed in a scene and alpha-blended over the layers below it. It carries view state only: registration is a scene-level transformation edge, not a property of the view. The concrete kind (ImageLayer, AnnotationLayer, PointLayer, TrackLayer, MeshLayer) carries its own data source and render settings. */
export type Layer = {
  blending: Blending;
  id: Scalars['ID']['output'];
  kind: LayerKind;
  opacity: Scalars['Float']['output'];
  order: Scalars['Int']['output'];
  /** The path of transformation edges from this layer's source coordinate system to its scene's WORLD system. A layer belongs to exactly one scene, so this is the one 'to world' question with a single right answer -- the path uses the layer's dataset facts plus this scene's membership edges, never another scene's registration. Null when the layer is unregistered or has no source system; empty when the source already is the world system. The server returns the edges; composing them (inverting flagged steps) stays the client's job */
  pathToWorld?: Maybe<Array<PlacementStep>>;
  /** Whether this layer has a place in its scene's world, and if not, why not. A null `pathToWorld` means two different things -- nobody has registered this data yet, or its geometry did not survive the operation that produced it and it can never be placed -- and a client should not have to guess which. UNREGISTERED is a gap to close; UNMAPPABLE is a fact to badge. Derived, never stored */
  placement: PlacementState;
  /** How much this layer's placement is actually known: the weakest edge on its path to world. UNKNOWN while the path rests on an assumed edge (an uncalibrated bootstrap mirror, or none at all); MANUAL once someone authored the registration; VALIDATED once it was checked. Derived, never stored -- and distinct from a single edge's `validity`: this is the minimum over the whole path */
  placementValidity: PlacementValidity;
  scene: Scene;
  visible: Scalars['Boolean']['output'];
};

export type LayerFilter = {
  AND?: InputMaybe<LayerFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<LayerFilter>;
  OR?: InputMaybe<LayerFilter>;
  blending?: InputMaybe<BlendingChoices>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  kind?: InputMaybe<LayerKindChoices>;
  /** Filter image layers by the lens they render */
  lens?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by the scene this layer is placed in */
  scene?: InputMaybe<Scalars['ID']['input']>;
};

/** The kind of a layer, discriminating which data source it renders and which rendering settings apply. */
export enum LayerKind {
  /** An annotation layer rendering the drawn vector geometry (polygons, boxes, ellipses, lines, paths) of an annotation collection. */
  Annotation = 'ANNOTATION',
  /** An image layer rendering array (lens) data through a composable render graph. */
  Image = 'IMAGE',
  /** A mesh layer rendering a 3D surface reconstruction. */
  Mesh = 'MESH',
  /** A point layer rendering a point cloud (e.g. SMLM localisations, centroids) from columns of a table. */
  Point = 'POINT',
  /** A track layer rendering trajectories from columns of a table, grouped by a track id. */
  Track = 'TRACK'
}

export enum LayerKindChoices {
  Annotation = 'ANNOTATION',
  Image = 'IMAGE',
  Mesh = 'MESH',
  Point = 'POINT',
  Track = 'TRACK'
}

/** A node in a layer's internal render graph. A 'channel' node carries an intensity source and transfer function; a 'phasor' node reduces an axis to a phasor and colors the pixel by it; a 'blend' node composites its children; a 'projection' node projects theirs over z. */
export type LayerNodeInput = {
  blending?: InputMaybe<Blending>;
  children?: InputMaybe<Array<LayerNodeInput>>;
  harmonic?: InputMaybe<Scalars['Int']['input']>;
  intensityAxis?: InputMaybe<Scalars['String']['input']>;
  intensityIndex?: InputMaybe<Scalars['Int']['input']>;
  kind: Scalars['String']['input'];
  label?: InputMaybe<Scalars['String']['input']>;
  mode?: InputMaybe<ProjectionMode>;
  phasorAxis?: InputMaybe<Scalars['String']['input']>;
  phasorTransfer?: InputMaybe<PhasorTransferInput>;
  transfer?: InputMaybe<TransferFunctionInput>;
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

export type LayerOrder =
  { id: Ordering; };

/** The composable render recipe inside a single layer, rooted at a blend node */
export type LayerRenderGraph = {
  __typename?: 'LayerRenderGraph';
  root: BlendNode;
};

/** The composable render recipe inside a single layer, rooted at a blend node */
export type LayerRenderGraphInput = {
  root: LayerNodeInput;
};

/** A node in a layer's internal render graph */
export type LayerRenderNode = {
  /** The discriminator of the node: 'channel', 'phasor', 'blend' or 'projection' */
  kind: Scalars['String']['output'];
  /** An optional human-readable label for the node */
  label?: Maybe<Scalars['String']['output']>;
};

/** A Lens is a way of looking at a dataset: a dimensional selection (slices) over a dataset that defines a view of its data */
export type Lens = {
  __typename?: 'Lens';
  activeAnchors: Array<CoordinateAnchor>;
  /** The lens' axis names, in array order. A selection never drops or reorders an axis */
  axisNames: Array<Scalars['String']['output']>;
  /** The coordinate system the lens' selection is expressed in. A sliced lens owns one (the space its slices cut out, with the derived edge recording the shift); an unsliced lens selects everything, so this resolves to the dataset's INTRINSIC system */
  coordinateSystem?: Maybe<CoordinateSystem>;
  dataset: ADataset;
  /** The datasets computed from this lens' selection: the direct other end of `derivedFrom`, which names a *lens* as a parent rather than a dataset. An unsliced lens reports what was derived from the whole intrinsic grid -- its space is that grid, so it can say nothing narrower. Like the forward field this reports every child, whether or not this lens is its primary parent and whether or not its geometry survived */
  derivedDatasets: Array<ADataset>;
  id: Scalars['ID']['output'];
  /** The most recent picture that shows this lens' dataset and nothing else -- the tile to put on this lens. The same picture the dataset itself reports: snapshots are taken of scenes, and sole occupancy is a fact about the dataset, so every lens over one dataset answers alike. Null when every scene it is placed in also holds other data */
  latestSnapshot?: Maybe<SceneSnapshot>;
  /** Everything needed to reduce one axis of this lens to a phasor: the bin count and width, the period the transform runs over, the laser rate, the instrument-response correction and the persisted distribution. Null when the lens has no MICROTIME or SPECTRUM axis. Derived -- none of it is stored on the lens, and a phasor render node references it rather than copying it, so two layers over one dataset cannot disagree about the instrument */
  phasor?: Maybe<PhasorContext>;
  /** Which axis of the data source maps to screen x, y, z, time and intensity. Derived from the axis types: spatial axes are in array order, so the last is x */
  renderAxes: RenderAxes;
  /** The shape this lens' slices cut out of its dataset */
  shape: Array<Scalars['Int']['output']>;
  slices: Array<Slice>;
  /** The edge from this lens' space back into its dataset's intrinsic pixel space. A crop is a translation of the slice starts; a stepped lens also rescales. Without this edge an ROI drawn on a cropped lens has no defined path back to its dataset. Null for an unsliced lens: its space IS the intrinsic space, and there is no shift to record */
  toParent?: Maybe<Transformation>;
};


/** A Lens is a way of looking at a dataset: a dimensional selection (slices) over a dataset that defines a view of its data */
export type LensPhasorArgs = {
  axis?: InputMaybe<Scalars['String']['input']>;
  harmonic?: Scalars['Int']['input'];
};

