/** A view attaching the optical path (light sources, filters, detectors and their connections) that light travelled through when this image region was acquired. */
export type LightpathViewCongruentViewsArgs = {
  filters?: InputMaybe<ViewFilter>;
  types?: InputMaybe<Array<ViewKind>>;
};

/** The duckdb half of a plan: look the sampled value up in the parquet. Bind order for `sql` is the parquet path/URL first (the read_parquet argument, supplied by the worker from its own access grant), then the key values in `keyColumns` order. Do not assume one row per point: (t, i) uniqueness is a convention no unique index backs, so the worker gets rows, plural */
export type LookupStep = {
  __typename?: 'LookupStep';
  /** What the SQL selects -- every declared non-coordinate column, never `*`. A column whose `references` names another table holds row ids of that table; following them is the client's choice, one more lookup away */
  attributes: Array<TableDatasetColumn>;
  /** The key bindings, in bind order: each names the value the worker holds (by axis name) and the parquet column it binds */
  keyColumns: Array<PlanKeyColumn>;
  /** The parameterized DuckDB statement: identifiers from validated declared columns and quoted, values as `?` placeholders, never interpolated. Bind the parquet path first, then the key values in `keyColumns` order. A non-duckdb consumer ignores this and reads `keyColumns` + `attributes` instead */
  sql: Scalars['String']['output'];
  /** The parquet store holding the rows. Ask it for an accessGrant to actually read it -- credentials and locations never appear in a plan */
  store: ParquetStore;
};

/** A permutation of axes, mapping each input axis to an output axis by name */
export type MapAxisTransformation = Transformation & {
  __typename?: 'MapAxisTransformation';
  createdAt: Scalars['DateTime']['output'];
  creator?: Maybe<User>;
  id: Scalars['ID']['output'];
  input?: Maybe<CoordinateSystem>;
  /** The names of the input axes, positionally matched to `outputAxes` */
  inputAxes: Array<Scalars['String']['output']>;
  kind: TransformKind;
  name?: Maybe<Scalars['String']['output']>;
  output?: Maybe<CoordinateSystem>;
  /** The names of the output axes, positionally matched to `inputAxes` */
  outputAxes: Array<Scalars['String']['output']>;
  /** Provenance entries for this edge: who authored it, and every refinement since. A refinement rewrites the edge in place and bumps `version`, so this audit trail is where the placement's earlier states live */
  provenanceEntries: Array<ProvenanceEntry>;
  /** How much this map is actually known: VALIDATED for a map the server derived (or one someone checked), INFERRED for numbers read from metadata, MANUAL for an authored registration, UNKNOWN for one the server assumed. A layer's validity is the weakest edge on its path to world */
  validity: PlacementValidity;
  /** (derivation edges) What the operation this edge records did to the *values*, orthogonal to `kind`: IDENTICAL (a crop -- statistics transfer), TRANSFORMED (a deconvolution -- same quantity, new numbers), CATEGORIZED (a threshold -- values became labels, and a bootstrapped scene renders the data as a label map). Null when unstated, and never present on a registration -- values do not cross a claim between spaces */
  valueRelation?: Maybe<ValueRelation>;
  version: Scalars['Int']['output'];
};


/** A permutation of axes, mapping each input axis to an output axis by name */
export type MapAxisTransformationProvenanceEntriesArgs = {
  pagination?: InputMaybe<OffsetPaginationInput>;
};

/** A view marking an image region as a semantic segmentation mask, where pixel values are class labels. It points to the reference view it was computed from and can carry a label table. */
