/** An immutable, versioned collection of meshes, backed by Parquet stores. Ask the catalog store for an access grant and query the Parquet directly (e.g. with DuckDB) rather than paginating meshes through GraphQL */
export type MeshCollection = {
  __typename?: 'MeshCollection';
  /** The Parquet store holding the catalog. Request an access grant from it and read the Parquet directly */
  catalog: ParquetStore;
  /** The coordinate system the collection's vertices are expressed in. The collection owns it; `derivedFrom` relates it to the data the meshes were extracted from */
  coordinateSystem: CoordinateSystem;
  /** The edge relating this collection's space to the space the meshes were extracted from -- an identity when the meshes are in that grid as-is, a scale when they came off a downsampled one. The same relation a derived dataset's `derivedFrom` records. Null for a mesh derived from no data at all */
  derivedFrom?: Maybe<Transformation>;
  /** The geometry encoding: how positions, normals and indices are quantized and compressed */
  encoding: Scalars['Any']['output'];
  /** The Parquet stores holding the geometry shards */
  geometry: Array<ParquetStore>;
  /** The octree grid. Its `cellSize` is in voxels of the coordinate system, so the octree aligns to the label grid the meshes were extracted from */
  grid: Scalars['Any']['output'];
  id: Scalars['ID']['output'];
  specVersion: Scalars['String']['output'];
  version: Scalars['String']['output'];
};

export type MeshCollectionFilter = {
  AND?: InputMaybe<MeshCollectionFilter>;
  DISTINCT?: InputMaybe<Scalars['Boolean']['input']>;
  NOT?: InputMaybe<MeshCollectionFilter>;
  OR?: InputMaybe<MeshCollectionFilter>;
  /** Filter by the coordinate system the mesh geometry is expressed in (the collection's own) */
  coordinateSystem?: InputMaybe<Scalars['ID']['input']>;
  /** Filter for items created after this datetime */
  createdAfter?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter for items created before this datetime */
  createdBefore?: InputMaybe<Scalars['DateTime']['input']>;
  /** Filter by the dataset the meshes were extracted from, following the derivation edge */
  dataset?: InputMaybe<Scalars['ID']['input']>;
  id?: InputMaybe<Scalars['ID']['input']>;
  /** Filter by list of IDs */
  ids?: InputMaybe<Array<Scalars['ID']['input']>>;
  /** Filter by the creator's subject ID */
  owner?: InputMaybe<Scalars['ID']['input']>;
  version?: InputMaybe<StrFilterLookup>;
};

/** A layer that renders a 3D mesh (surface reconstruction / isosurface) placed and styled in a scene. */
export type MeshLayer = Layer & {
  __typename?: 'MeshLayer';
  blending: Blending;
  /** The versioned, coordinate-system-anchored mesh collection this layer renders. Its geometry is fetched from the collection's Parquet catalog, not through this API */
  collection?: Maybe<MeshCollection>;
  id: Scalars['ID']['output'];
  kind: LayerKind;
  materialColor?: Maybe<Array<Scalars['Int']['output']>>;
  opacity: Scalars['Float']['output'];
  order: Scalars['Int']['output'];
  /** The path of transformation edges from this layer's source coordinate system to its scene's WORLD system. A layer belongs to exactly one scene, so this is the one 'to world' question with a single right answer -- the path uses the layer's dataset facts plus this scene's membership edges, never another scene's registration. Null when the layer is unregistered or has no source system; empty when the source already is the world system. The server returns the edges; composing them (inverting flagged steps) stays the client's job */
  pathToWorld?: Maybe<Array<PlacementStep>>;
  /** Whether this layer has a place in its scene's world, and if not, why not. A null `pathToWorld` means two different things -- nobody has registered this data yet, or its geometry did not survive the operation that produced it and it can never be placed -- and a client should not have to guess which. UNREGISTERED is a gap to close; UNMAPPABLE is a fact to badge. Derived, never stored */
  placement: PlacementState;
  /** How much this layer's placement is actually known: the weakest edge on its path to world. UNKNOWN while the path rests on an assumed edge (an uncalibrated bootstrap mirror, or none at all); MANUAL once someone authored the registration; VALIDATED once it was checked. Derived, never stored -- and distinct from a single edge's `validity`: this is the minimum over the whole path */
  placementValidity: PlacementValidity;
  scene: Scene;
  visible: Scalars['Boolean']['output'];
  wireframe: Scalars['Boolean']['output'];
};

