/** The instrument-response correction taking a raw phasor to a calibrated one, pinned to a coordinate anchor. An acquisition fact, not a display choice: two layers over one dataset cannot coherently disagree about it. Its absence means the phasor is uncalibrated, which still renders */
export type PhasorCalibration = {
  __typename?: 'PhasorCalibration';
  axis: Scalars['String']['output'];
  harmonic: Scalars['Int']['output'];
  id: Scalars['ID']['output'];
  modulationFactor?: Maybe<Scalars['Float']['output']>;
  phaseOffset?: Maybe<Scalars['Float']['output']>;
  reference?: Maybe<Scalars['String']['output']>;
};

/** Input type for an instrument-response correction: the phase offset and modulation factor taking a raw phasor to a calibrated one */
export type PhasorCalibrationInput = {
  /** The axis the correction applies to */
  axis: Scalars['String']['input'];
  /** The harmonic the correction applies at */
  harmonic?: InputMaybe<Scalars['Int']['input']>;
  /** The modulation correction */
  modulationFactor?: InputMaybe<Scalars['Float']['input']>;
  /** The phase correction in radians */
  phaseOffset?: InputMaybe<Scalars['Float']['input']>;
  /** What the correction was measured against */
  reference?: InputMaybe<Scalars['String']['input']>;
};

/** What a phasor render node derives a pixel's color from. */
export enum PhasorColorMode {
  /** The mean of the phase- and modulation-derived values. */
  Average = 'AVERAGE',
  /** The modulus of the phasor. Over a microtime axis this is the modulation lifetime (tau_m); it exceeds tau_phi exactly when the decay is multi-exponential. */
  Modulation = 'MODULATION',
  /** The angle of the phasor. Over a microtime axis this is the phase lifetime (tau_phi); over a spectrum axis, the spectral centre of mass. */
  Phase = 'PHASE'
}

/** Everything needed to reduce one axis of a lens to a phasor, at one harmonic. Derived from the dataset's calibration, its lightpath and its phasor spokes; nothing here is stored on the lens. A phasor render node states *which* axis and harmonic to reduce, and reads the rest from here -- the instrument is an acquisition fact, so two layers over one dataset cannot disagree about it */
export type PhasorContext = {
  __typename?: 'PhasorContext';
  /** The axis the phasor is taken over */
  axis: Scalars['String']['output'];
  /** What that axis samples: MICROTIME (so the phase reads as a fluorescence lifetime) or SPECTRUM (so it reads as a spectral centre of mass) */
  axisType: AxisType;
  /** The physical width of one bin, from the axis' PHYSICAL calibration: a duration ('0.098 ns') for a microtime axis, a wavelength step ('5 nm') for a spectrum axis. Null when the dataset has no calibration -- the phasor is then computable only in bin units */
  binWidth?: Maybe<Scalars['GenericQuantity']['output']>;
  /** The number of bins along that axis on this lens: the N of the transform */
  bins: Scalars['Int']['output'];
  /** The instrument-response correction at this axis and harmonic. Null means the phasor is uncalibrated -- which still renders, its hue is just not traceable to an absolute lifetime */
  calibration?: Maybe<PhasorCalibration>;
  /** The harmonic this context was resolved for. It selects the calibration and the distribution below, which are both harmonic-specific */
  harmonic: Scalars['Int']['output'];
  /** The repetition rate of the pulsed source, read from the lightpath graph anchored to this data: the clock a FLIM phasor runs on, and what makes a phase an absolute lifetime. Prefer it over `window` for a lifetime, and note the two diverge on a lens that crops its microtime axis. Null for a spectrum axis, or when no lightpath states a rate */
  laserFrequency?: Maybe<Scalars['Frequency']['output']>;
  /** The persisted (g, s) density at this axis and harmonic, so a client can range the overlay's colormap without reading the cube. Null until a task has computed one */
  phasorHistogram?: Maybe<PhasorHistogram>;
  /** The period the transform actually runs over on THIS lens: bin_width x bins. It is the frequency to transform at, and the only one available over a spectrum axis. For an uncropped FLIM axis it should agree with laserFrequency -- but a lens that slices its phasor axis narrows it, and then it deliberately does not: the window follows the data, while the laser does not. Null when there is no calibration */
  window?: Maybe<Scalars['GenericQuantity']['output']>;
};

/** A region of phasor space, and the color the pixels falling inside it are painted */
export type PhasorCursor = {
  __typename?: 'PhasorCursor';
  color?: Maybe<Array<Scalars['Int']['output']>>;
  g?: Maybe<Scalars['Float']['output']>;
  kind: PhasorCursorKind;
  label?: Maybe<Scalars['String']['output']>;
  points?: Maybe<Array<Array<Scalars['Float']['output']>>>;
  radius?: Maybe<Scalars['Float']['output']>;
  s?: Maybe<Scalars['Float']['output']>;
  visible: Scalars['Boolean']['output'];
};

/** A region of phasor space, and the color the pixels falling inside it are painted. A color rule on the image, not a plot widget */
export type PhasorCursorInput = {
  color?: InputMaybe<Array<Scalars['Int']['input']>>;
  g?: InputMaybe<Scalars['Float']['input']>;
  kind?: InputMaybe<PhasorCursorKind>;
  label?: InputMaybe<Scalars['String']['input']>;
  points?: InputMaybe<Array<Array<Scalars['Float']['input']>>>;
  radius?: InputMaybe<Scalars['Float']['input']>;
  s?: InputMaybe<Scalars['Float']['input']>;
  visible?: InputMaybe<Scalars['Boolean']['input']>;
};

/** The shape of a region selected in phasor space. */
export enum PhasorCursorKind {
  /** A disc, given by its centre (g, s) and a radius. */
  Circle = 'CIRCLE',
  /** An arbitrary closed region, given by at least three (g, s) vertices. */
  Polygon = 'POLYGON'
}

/** The distribution of a phasor pinned to a coordinate anchor: a 2D (g, s) density plus the summed profile it was computed from. What ValueHistogram is to an intensity channel -- it lets a client pick a sane value range for a phasor overlay without reading the cube */
export type PhasorHistogram = {
  __typename?: 'PhasorHistogram';
  axis: Scalars['String']['output'];
  bins: Scalars['Int']['output'];
  calibrated: Scalars['Boolean']['output'];
  /** The flattened bins x bins (g, s) density, row-major with s outermost */
  counts: Array<Scalars['Float']['output']>;
  gMax: Scalars['Float']['output'];
  gMin: Scalars['Float']['output'];
  harmonic: Scalars['Int']['output'];
  id: Scalars['ID']['output'];
  /** The summed profile along the phasor axis (a decay for a MICROTIME axis, a spectrum for a SPECTRUM one), one value per bin */
  profile: Array<Scalars['Float']['output']>;
  sMax: Scalars['Float']['output'];
  sMin: Scalars['Float']['output'];
  total?: Maybe<Scalars['Int']['output']>;
};

/** Input type for a phasor distribution: the 2D (g, s) density of a phasor taken over one axis at one harmonic, plus the summed profile it came from. Persisted so a client can pick a value range for a phasor overlay without reading the cube */
export type PhasorHistogramInput = {
  /** The axis the phasor was taken over */
  axis: Scalars['String']['input'];
  /** The resolution of the square (g, s) density grid */
  bins?: InputMaybe<Scalars['Int']['input']>;
  calibrated?: InputMaybe<Scalars['Boolean']['input']>;
  /** The flattened bins x bins density */
  counts: Array<Scalars['Float']['input']>;
  gMax?: InputMaybe<Scalars['Float']['input']>;
  gMin?: InputMaybe<Scalars['Float']['input']>;
  /** The harmonic the phasor was taken at */
  harmonic?: InputMaybe<Scalars['Int']['input']>;
  profile?: InputMaybe<Array<Scalars['Float']['input']>>;
  sMax?: InputMaybe<Scalars['Float']['input']>;
  sMin?: InputMaybe<Scalars['Float']['input']>;
  total?: InputMaybe<Scalars['Int']['input']>;
};

/** Reduces one axis of the lens to a phasor -- the DFT of each pixel's profile along it, at a harmonic -- and colors the pixel by the result. Over a microtime axis the phase reads as a fluorescence lifetime; over a spectrum axis, as a spectral centre of mass. Its output is a raster that composites into the scene like any other leaf, not a scatter plot */
export type PhasorNode = LayerRenderNode & {
  __typename?: 'PhasorNode';
  harmonic: Scalars['Int']['output'];
  intensityAxis?: Maybe<Scalars['String']['output']>;
  intensityIndex: Scalars['Int']['output'];
  kind: Scalars['String']['output'];
  /** An optional human-readable label for the node */
  label?: Maybe<Scalars['String']['output']>;
  phasorAxis: Scalars['String']['output'];
  transfer: PhasorTransfer;
  visible: Scalars['Boolean']['output'];
};

/** How a phasor becomes the pixel's color. The transfer function of a phasor source: it maps the reduction's output -- a (g, s) pair plus a photon count -- rather than a sampled scalar, which is why it is not a TransferFunction */
export type PhasorTransfer = {
  __typename?: 'PhasorTransfer';
  colormap: ColorMap;
  cursors: Array<PhasorCursor>;
  intensity: TransferFunction;
  max?: Maybe<Scalars['GenericQuantity']['output']>;
  min?: Maybe<Scalars['GenericQuantity']['output']>;
  mode: PhasorColorMode;
  weightByIntensity: Scalars['Boolean']['output'];
};

/** How a phasor becomes the pixel's color: the transfer function of a phasor source */
export type PhasorTransferInput = {
  colormap?: InputMaybe<ColorMap>;
  cursors?: InputMaybe<Array<PhasorCursorInput>>;
  intensity?: InputMaybe<TransferFunctionInput>;
  max?: InputMaybe<Scalars['GenericQuantity']['input']>;
  min?: InputMaybe<Scalars['GenericQuantity']['input']>;
  mode?: InputMaybe<PhasorColorMode>;
  weightByIntensity?: InputMaybe<Scalars['Boolean']['input']>;
};

