/** Whether a layer has a place in its scene's world, and if not, why not. Derived, never stored. */
export enum PlacementState {
  /** The layer's data reaches the scene's world: `pathToWorld` is the route. */
  Placed = 'PLACED',
  /** This layer's data can never be placed: it reaches the world only across an UNMAPPABLE edge, which declares that no point correspondence exists. `pathToWorld` is null because there is nothing to find — badge it, and do not go looking for the missing registration. */
  Unmappable = 'UNMAPPABLE',
  /** Nothing yet relates this layer's data to the scene's world. `pathToWorld` is null because the registration is *missing* — this is a gap in the data, and authoring the edge closes it. */
  Unregistered = 'UNREGISTERED'
}

/** One step of a placement path: a transformation edge, plus whether it is traversed against its stored direction. The server returns the steps; composing them into a matrix is the client's job (invert the flagged ones first) */
export type PlacementStep = {
  __typename?: 'PlacementStep';
  /** True when the edge is traversed output-to-input; the client must invert it before composing */
  inverted: Scalars['Boolean']['output'];
  /** The transformation edge this step walks along */
  transformation: Transformation;
};

/** How much a transformation edge's map is actually known: assumed by the server, inferred from metadata, authored by someone, or validated against the data. A layer's validity is derived from it, never stored: the weakest edge on its path to world. */
export enum PlacementValidity {
  /** The numbers were read from acquisition metadata (a pixel size, a stage pose). As right as the metadata is. */
  Inferred = 'INFERRED',
  /** Someone authored this map -- a registration pipeline, a human with a matrix. It exists on purpose, but nothing has checked it against the data. */
  Manual = 'MANUAL',
  /** This map was assumed, never measured -- badge it. The one writer left is the scene bootstrap mirroring an uncalibrated dataset's pixels into a world under default units; it also remains on historical auto-registered edges. */
  Unknown = 'UNKNOWN',
  /** Exact or checked: either the server derived the map from shapes and slices, so it cannot be wrong, or someone validated an authored registration against the data. */
  Validated = 'VALIDATED'
}

/** One key binding of a lookup: the sampled or passthrough value named `axis` binds the parquet column `column`. For a depth-1 plan the two names coincide by construction (a coordinate column and its derived axis are the same fact), but the worker should always bind by this pair: values live under axis names, columns live in a file, and the plan is the bridge */
export type PlanKeyColumn = {
  __typename?: 'PlanKeyColumn';
  /** The name the worker holds the value under: a passthrough axis of the sampled array (e.g. `t`) or an axis the sample produced (e.g. `i`) */
  axis: Scalars['String']['output'];
  /** The declared coordinate column this value binds, carrying the parquet column name and its dtype */
  column: TableDatasetColumn;
};

/** A channel descriptor */
export type PlaneInfo = {
  __typename?: 'PlaneInfo';
  label: Scalars['String']['output'];
};

/** A layer that renders a point cloud (e.g. SMLM localisations, centroids) from a table dataset. */
export type PointLayer = Layer & {
  __typename?: 'PointLayer';
  blending: Blending;
  colorColumn?: Maybe<Scalars['String']['output']>;
  colormap?: Maybe<ColorMap>;
  id: Scalars['ID']['output'];
  /** The dataset's ID-role column identifying each point, if any */
  idColumn?: Maybe<Scalars['String']['output']>;
  kind: LayerKind;
  opacity: Scalars['Float']['output'];
  order: Scalars['Int']['output'];
  /** The path of transformation edges from this layer's source coordinate system to its scene's WORLD system. A layer belongs to exactly one scene, so this is the one 'to world' question with a single right answer -- the path uses the layer's dataset facts plus this scene's membership edges, never another scene's registration. Null when the layer is unregistered or has no source system; empty when the source already is the world system. The server returns the edges; composing them (inverting flagged steps) stays the client's job */
  pathToWorld?: Maybe<Array<PlacementStep>>;
  /** Whether this layer has a place in its scene's world, and if not, why not. A null `pathToWorld` means two different things -- nobody has registered this data yet, or its geometry did not survive the operation that produced it and it can never be placed -- and a client should not have to guess which. UNREGISTERED is a gap to close; UNMAPPABLE is a fact to badge. Derived, never stored */
  placement: PlacementState;
  /** How much this layer's placement is actually known: the weakest edge on its path to world. UNKNOWN while the path rests on an assumed edge (an uncalibrated bootstrap mirror, or none at all); MANUAL once someone authored the registration; VALIDATED once it was checked. Derived, never stored -- and distinct from a single edge's `validity`: this is the minimum over the whole path */
  placementValidity: PlacementValidity;
  pointSize?: Maybe<Scalars['Float']['output']>;
  scene: Scene;
  sizeColumn?: Maybe<Scalars['String']['output']>;
  /** The coordinate column whose axis is named 't', if any */
  tColumn?: Maybe<Scalars['String']['output']>;
  /** The table dataset the points are drawn from. Its declared coordinate columns provide the coordinates and its own system provides the placement -- the column fields below are derived from its schema, never stored per layer */
  tableDataset: TableDataset;
  visible: Scalars['Boolean']['output'];
  /** The coordinate column whose axis is named 'x', from the dataset's declared schema */
  xColumn?: Maybe<Scalars['String']['output']>;
  /** The coordinate column whose axis is named 'y' */
  yColumn?: Maybe<Scalars['String']['output']>;
  /** The coordinate column whose axis is named 'z', if any */
  zColumn?: Maybe<Scalars['String']['output']>;
};

export enum PortRole {
  Input = 'INPUT',
  Output = 'OUTPUT'
}

/** Optional 3D pose; position and/or orientation can be omitted */
export type Pose3D = {
  __typename?: 'Pose3D';
  orientation?: Maybe<Euler>;
  position?: Maybe<Vec3>;
};

/** A 3D pose consisting of position and orientation. */
export type Pose3DInput = {
  orientation?: InputMaybe<EulerInput>;
  position?: InputMaybe<Vec3Input>;
};

/** How a viewer should open a scene: flat, volumetric, or its own choice. */
export enum PreferredView {
  /** No preference stated -- the viewer decides, e.g. from whether the data has a z axis with depth. The default: a scene nobody has expressed a preference for should not claim one. */
  Auto = 'AUTO',
  /** Open volumetric: the projection view, looking at the data as a body. */
  ThreeD = 'THREE_D',
  /** Open flat: the cross-section view, one slice at a time. */
  TwoD = 'TWO_D'
}

/** The 3D projection / rendering mode applied to a volumetric (z-stacked) render node. */
export enum ProjectionMode {
  /** Attenuated maximum intensity projection, weighting samples by depth so nearer samples dominate. */
  AttenuatedMip = 'ATTENUATED_MIP',
  /** Isosurface rendering: a surface is extracted at a threshold value. */
  Isosurface = 'ISOSURFACE',
  /** Maximum intensity projection: each output pixel takes the maximum value along the z-axis. */
  Mip = 'MIP',
  /** Alpha volume rendering: samples along z are alpha-composited front-to-back. */
  Volume = 'VOLUME'
}

/** Projects the composite of its children through the z-axis using a 3D rendering mode */
export type ProjectionNode = LayerRenderNode & {
  __typename?: 'ProjectionNode';
  children: Array<LayerRenderNode>;
  kind: Scalars['String']['output'];
  /** An optional human-readable label for the node */
  label?: Maybe<Scalars['String']['output']>;
  mode: ProjectionMode;
};

/** A provenance event for a model. */
export type ProvenanceEntry = {
  __typename?: 'ProvenanceEntry';
  client?: Maybe<Client>;
  /** The date of the change. */
  date: Scalars['DateTime']['output'];
  /** The effective changes made to the model. */
  effectiveChanges: Array<ModelChange>;
  /** The ID of the history entry. */
  id: Scalars['ID']['output'];
  /** The type of change that was made. */
  kind: HistoryKind;
  /** The task during which the change occurred, if any. */
  task?: Maybe<Task>;
  /** User who made the change. */
  user?: Maybe<User>;
};

export enum PulseKind {
  Cw = 'CW',
  ModeLocked = 'MODE_LOCKED',
  Other = 'OTHER',
  Qswitched = 'QSWITCHED',
  Repetitive = 'REPETITIVE',
  Single = 'SINGLE'
}

export type Query = {
  __typename?: 'Query';
  _entities: Array<Maybe<_Entity>>;
  _service: _Service;
  /** List acquisition views (recording when and by whom images were acquired) */
  acquisitionViews: Array<AcquisitionView>;
  /** Get all active views for a specific image */
  activeViews: Array<View>;
  /** Get a single array dataset by ID */
  adataset: ADataset;
  /** List array datasets (N-dimensional arrays with named dimensions and anchored metadata) */
  adatasets: Array<ADataset>;
  /** List affine transformation views (placing images in physical stage space) */
  affineTransformationViews: Array<AffineTransformationView>;
  /** Get a single animation by ID */
  animation: Animation;
  /** List animations (named camera tours through a scene) */
  animations: Array<Animation>;
  /** Get a single annotation by ID */
  annotation: Annotation;
  /** Get a single annotation collection by ID */
  annotationCollection: AnnotationCollection;
  /** List annotation collections (named sets of human-drawn shapes, each owning the coordinate system they are drawn in) */
  annotationCollections: Array<AnnotationCollection>;
  /** List annotations (human-drawn shapes, each in its collection's coordinate system) */
  annotations: Array<Annotation>;
  /** Every attribute plan reachable from one system: one per FIELD edge landing on a table, discovered across the fact component -- probe a source image and the plans of the instance mask derived from it come back, each carrying the `path` of steps from the probed system to its root. Registrations are never crossed (no scene, no world). A plan is instructions, never attributes -- map along the path, sample this array, look the value up in this parquet -- and takes no coordinate, so a client fetches it once and executes it per hover against the chunks it is already rendering. Cache it against the FIELD edge plus every path step (ids and versions); `maxDepth` bounds the discovery. The server reads no store and composes nothing */
  attributePlans: Array<AttributePlan>;
  /** Get available permissions for a specific identifier */
  availablePermissions: Array<PermissionOption>;
  /** Get a single camera by ID */
  camera: Camera;
  /** List channel views (describing the channels of images) */
  channelViews: Array<ChannelView>;
  /** Get the channel infos of a specific image */
  channelsFor: Array<ChannelInfo>;
  /** List the child datasets of a dataset */
  children: Array<DatasetImageFile>;
  /** List continuous scan views (recording scan directions) */
  continousScanViews: Array<ContinousScanView>;
  /** Walk the coordinate graph out from one system: every coordinate system it reaches and every top-level edge between them. Reachability is undirected (an edge pointing into the system relates to it as much as one pointing out), the edges keep their true direction, and nothing is composed -- what the list queries cannot answer is 'which edges relate to *this* one', because relatedness is transitive and a filter is not */
  coordinateGraph: CoordinateGraph;
  /** Get a single coordinate system by ID */
  coordinateSystem: CoordinateSystem;
  /** List coordinate systems (the nodes of the RFC-5 coordinate graph) */
  coordinateSystems: Array<CoordinateSystem>;
  /** Get a single data array by ID */
  dataArray: DataArray;
  /** List data arrays (the multiscale zarr arrays backing array datasets) */
  dataArrays: Array<DataArray>;
  /** Get a single dataset by ID */
  dataset: Dataset;
  /** List datasets (folder-like collections of images, files and tables) */
  datasets: Array<Dataset>;
  /** Get generic key-value descriptors for an object identified by identifier and ID */
  describe: Array<Descriptor>;
  /** List eras (named time epochs on a microscope that timepoint views anchor to) */
  eras: Array<Era>;
  /** Get a single experiment by ID */
  experiment: Experiment;
  /** List experiments */
  experiments: Array<Experiment>;
  /** Get a single file by ID */
  file: File;
  /** Get a single file view by ID */
  fileView: FileView;
  /** List file views (linking images to the raw files they were converted from) */
  fileViews: Array<FileView>;
  /** List files (raw microscopy files such as .czi or .ome.tiff) */
  files: Array<File>;
  /** Returns a single image by ID */
  image: Image;
  /** List image accessors (columns of tables that reference images) */
  imageAccessors: Array<ImageAccessor>;
  /** List images in the current organization, filterable and orderable */
  images: Array<Image>;
  /** Get statistics about images */
  imagesStats: ImageStats;
  /** Get one labelled instance of an instance mask by its compound ID (maskId-rowId) */
  instanceMaskViewLabel: InstanceMaskViewLabel;
  /** Get a single instrument by ID */
  instrument: Instrument;
  /** List microscopes/instruments */
  instruments: Array<Instrument>;
  /** List label accessors (columns of tables that reference mask labels) */
  labelAccessors: Array<LabelAccessor>;
  /** List label views (mapping image channels to labels) */
  labelViews: Array<LabelView>;
  /** Get a single layer by ID */
  layer: Layer;
  /** List layers placed in scenes (a heterogeneous list of layer kinds) */
  layers: Array<Layer>;
  /** Get a single lens by ID */
  lens: Lens;
  /** List lenses (parameterized ways of looking at an array dataset) */
  lenses: Array<Lens>;
  /** Get a single lightpath view by ID */
  lightpathView: LightpathView;
  /** Get display information (label and color) for one pixel value of a mask */
  maskedPixelInfo: MaskedPixelInfo;
  /** List the memberships of the current organization (excluding bots) */
  members: Array<Membership>;
  /** Get a single mesh collection by ID */
  meshCollection: MeshCollection;
  /** List mesh collections (immutable, versioned Parquet-backed mesh sets, each in a coordinate system of its own) */
  meshCollections: Array<MeshCollection>;
  /** Get a single multi well plate by ID */
  multiWellPlate: MultiWellPlate;
  /** List multi well plates */
  multiWellPlates: Array<MultiWellPlate>;
  /** List datasets created by the current user */
  mydatasets: Array<Dataset>;
  /** List eras created by the current user */
  myeras: Array<Era>;
  /** List files created by the current user */
  myfiles: Array<File>;
  /** List images created by the current user */
  myimages: Array<Image>;
  /** List objectives created by the current user */
  myobjectives: Array<Objective>;
  /** List snapshots created by the current user */
  mysnapshots: Array<Snapshot>;
  /** List tables created by the current user */
  mytables: Array<Table>;
  /** The k annotations of one collection nearest to a point, by cube distance between the point and each annotation's intrinsic bounding box (GiST-accelerated; 0 inside the box). Scoped to one collection because boxes only compare within one frame; the point is in the collection's nearest-intrinsic space, in its coordinate order */
  nearestAnnotations: Array<Annotation>;
  /** Get a single objective by ID */
  objective: Objective;
  /** List microscope objectives */
  objectives: Array<Objective>;
  /** Get permissions for a specific object */
  permissions: Array<UserObjectPermission>;
  /** Get a random image of the current organization */
  randomImage: Image;
  /** Get a single render tree by ID */
  renderTree: RenderTree;
  /** List render trees (saved client-side render configurations) */
  renderTrees: Array<RenderTree>;
  /** Get a single RGB render view by ID */
  rgbView: RgbView;
  /** List RGB render views (per-channel display settings) */
  rgbViews: Array<RgbView>;
  /** Get a single RGB render context by ID */
  rgbcontext: RgbContext;
  /** List RGB render contexts (groups of RGB views composing a displayable image) */
  rgbcontexts: Array<RgbContext>;
  /** Get a single region of interest by ID */
  roi: Roi;
  /** List regions of interest drawn on images */
  rois: Array<Roi>;
  /** List the rows of a table */
  rows: Array<Scalars['MetricMap']['output']>;
  /** List scale views (the levels of multiscale image pyramids) */
  scaleViews: Array<ScaleView>;
  /** Get a single scene by ID */
  scene: Scene;
  /** Get a single scene snapshot by ID */
  sceneSnapshot: SceneSnapshot;
  /** List scene snapshots (pre-rendered pictures of a composition, for previewing it without compositing the layers) */
  sceneSnapshots: Array<SceneSnapshot>;
  /** List scenes (compositions of layers over array datasets) */
  scenes: Array<Scene>;
  /** Get a single snapshot by ID */
  snapshot: Snapshot;
  /** List snapshots (pre-rendered thumbnail images of images) */
  snapshots: Array<Snapshot>;
  /** Get a single stage by ID */
  stage: Stage;
  /** List stages (the 3D physical spaces images are positioned in) */
  stages: Array<Stage>;
  /** Get a single table by ID */
  table: Table;
  /** Get a single table cell by its compound ID (tableId-rowId-columnId) */
  tableCell: TableCell;
  /** List the cells of a table, row-major over the table's parquet data */
  tableCells: Array<TableCell>;
  /** Get a single table dataset by ID */
  tableDataset: TableDataset;
  /** List table datasets (Parquet-backed tables of scientific records: measurements, localizations, expression levels) */
  tableDatasets: Array<TableDataset>;
  /** Get a single table row by its compound ID (tableId-rowId) */
  tableRow: TableRow;
  /** List the rows of a table, paginated over the table's parquet data */
  tableRows: Array<TableRow>;
  /** List tables (tabular data backed by parquet stores) */
  tables: Array<Table>;
  /** Get a single Rekuest task by ID */
  task: Task;
  /** List the Rekuest tasks under which objects were created or changed */
  tasks: Array<Task>;
  /** List timepoint views (anchoring image regions in real time) */
  timepointViews: Array<TimepointView>;
  /** Get a single transformation by ID */
  transformation: Transformation;
  /** List transformations (the directed edges of the coordinate graph). Compose them client-side; the server never resolves a path to world, because the same dataset can sit in two scenes under two registrations */
  transformations: Array<Transformation>;
  /** List well position views (mapping images to multi well plate wells) */
  wellPositionViews: Array<WellPositionView>;
};


