  /** Filter to table datasets placeable into this scene: those whose coordinate system has a traversable path to the scene's world, walking the transformation edges under the scene's membership */
  placeableIn?: InputMaybe<Scalars['ID']['input']>;
  /** Search by name (case-insensitive substring) */
